var PD=[{"n":"アオキ","f":"ミズキ科","t":"常緑広葉樹","fl":"3～5","h":"1～2","su":"△","w":"中","c":"◎","dw":"〇～△","al":"","p":"アザミウマ\nアブラムシ\nカイガラムシ\nケムシ\nシャクトリムシ\nうどんこ病\n炭疽病","d":"冬の庭を彩る貴重な樹種です。さらに冬には赤くつやのある美しい果実をつけますが、果実は雌株のみに実ります。花は目立たず、観賞の対象は赤い実と、光沢のある大きな葉です。耐陰性が高いため、直射日光が当たらない場所でも生育するのでシェードガーデン(日陰の庭)などでもたいへん重宝します。","pr":"冬期","nt":"","td":"△","so":"壌"},{"n":"アオダモ（コバノトネリコ）","f":"モクセイ科","t":"落葉広葉樹","fl":"4～5","h":"7～10","su":"◎～〇","w":"中","c":"〇","dw":"〇","al":"赤","p":"テッポウムシ\nミノムシ","d":"高級バットの材料木として知られます。庭木としての利用は少なかったものの、春先に咲く花、涼しげな枝ぶり、幹に浮かぶ白点に観賞価値があるとして、雑木の庭を中心に個人の庭にも植えられるようになりました。花は遠目に見ると樹冠に雪が降り積もったように、あるいは煙が立ち上がっているように見えます。","pr":"1～3月","nt":"","td":"〇","so":"壌土"},{"n":"アオハダ","f":"モチノキ科","t":"落葉広葉樹","fl":"5～6","h":"7～10","su":"〇～△","w":"少","c":"","dw":"〇","al":"","p":"カイガラムシ","d":"葉の先は鋭くとがり、縁にはとがった鋸歯が多数ある。","pr":"冬期","nt":"","td":"△","so":"湿壌"},{"n":"アカシデ","f":"カバノキ科","t":"落葉広葉樹","fl":"3～4月","h":"5～7","su":"◎～〇","w":"少","c":"◎","dw":"◎","al":"赤/黄","p":"テッポウムシ","d":"ケヤキに似た箒状に育ちますが、ケヤキほど大きくはなりません。長く垂れ下がる雄花が紙垂（シデ：玉串につけて垂らす紙）に似ていることから～シデと呼ばれます。幹は年数を経ると次第に縦に割れ模様が入り、非常に美しく鑑賞価値があります。","pr":"","nt":"","td":"△","so":"全土"},{"n":"アカバナアセビ","f":"ツツジ科","t":"常緑広葉樹","fl":"4","h":"2～3","su":"〇～△","w":"","c":"◎","dw":"◎～〇","al":"赤/黄","p":"ほとんどない","d":"花殻を摘むと樹勢が衰えない。移植は容易で、耐寒性がある。","pr":"花後、秋","nt":"葉に毒性がある。","td":"〇","so":"壌"},{"n":"アジサイ","f":"アジサイ科","t":"落葉広葉樹","fl":"6～7","h":"1～2","su":"〇～△","w":"","c":"◎","dw":"◎～〇","al":"","p":"","d":"本来は、広い場所でのびのびと育てるほうがよい。強剪定を避ける。","pr":"7月","nt":"大気汚染に強い。","td":"〇","so":"湿壌"},{"n":"アズキナシ","f":"バラ科","t":"落葉広葉樹","fl":"","h":"5～7","su":"◎～△","w":"","c":"〇","dw":"〇","al":"赤/黄","p":"","d":"アズキナシの名前は、この果実が野生のナシ類に似ており、小豆のように小さいことに由来しています。葉は秋になるとややくすんだオレンジ色に黄葉します。自然系が美しく、自然風庭園によく使われます。","pr":"","nt":"","td":"△","so":"全土"},{"n":"アスチルベ","f":"ユキノシタ科","t":"宿根","fl":"5～7月","h":"","su":"△","w":"","c":"◎","dw":"△","al":"","p":"花色にはピンク,赤,白,紫があります。アブラムシ、ヨトウムシ","d":"初夏の庭を明るく彩り、半日陰のシェードガーデンにも向く花で、梅雨の長雨にも花が傷むことなく元気に咲き続けます。円錐形の優雅で綿菓子のような花穂を伸ばし、こんもり茂った葉とのバランスもよく、安定した草姿が魅力です。花色が多くバラエティに富みます。","pr":"","nt":"","td":"△","so":"壌"},{"n":"アセビ","f":"ツツジ科","t":"常緑広葉樹","fl":"3～4","h":"1～2","su":"◎～〇","w":"","c":"△","dw":"〇","al":"","p":"グンバイムシ\nハマキムシ","d":"早春に穂になって咲く小さな白い花や、紅色の新芽、濃い緑色の葉が美しいアセビには、芸品種も数多くあります。葉や茎には、有毒のアセトポキシンが含まれているため、馬が食べると毒にあたって酔ったようにふらふらとした足取りになることから、漢名で馬酔木（アセビ）と書かれるようになったとされます。","pr":"4～5月","nt":"","td":"△","so":"埴壌"},{"n":"アベリア(ハナツクバネウツギ)","f":"スイカズラ科","t":"常緑広葉樹","fl":"6～11","h":"2～3","su":"〇～△","w":"","c":"◎","dw":"◎～〇","al":"","p":"ほとんどない","d":"乾燥に強く、刈込みによく耐える。","pr":"11～3月、夏","nt":"","td":"△","so":"砂"},{"n":"アベリア・ホープレイズ","f":"スイカズラ科","t":"常緑広葉樹","fl":"6～11月","h":"","su":"◎～〇","w":"少","c":"◎","dw":"◎","al":"","p":"ほとんどない","d":"アベリアの園芸品種で、葉の縁が黄色～白色の色があるカラーリーフです。花が咲き、葉がきれいで丈夫なのが人気の理由です。成長が遅くてあまり手がかからない優れものです。明るいイメージにぴったりです。","pr":"","nt":"","td":"△","so":"全土"},{"n":"アマドコロ","f":"キジカクシ科","t":"宿根","fl":"5","h":"","su":"◎～△","w":"","c":"◎","dw":"◎～〇","al":"","p":"さび病\nコウモリガ","d":"名前の由来は、太い根茎の形がトコロ（ヤマノイモ）に似ていて、甘みがあることによります。春の新芽は山菜として食用にされます。ただし、果実は有毒です。観賞用に栽培されるのは、主に葉に白い覆輪が入る品種です。清涼感があり、庭やコンテナを明るく彩り、葉はフラワーアレンジメントなどの花材としても広く利用されています。茎は弓なりにやや湾曲し、春にスズランのように下向きの花を咲かせます。地中では太い根茎が枝分かれしながら広がり、群生させると見ごたえがあります。","pr":"","nt":"","td":"△","so":"全土"},{"n":"アメリカデイゴ","f":"マメ科","t":"落葉広葉樹","fl":"8～10","h":"4～5","su":"","w":"","c":"△","dw":"","al":"","p":"","d":"茎と葉の中央葉脈に棘があり、葉は互生したまご型をしている。","pr":"８月","nt":"","td":"〇","so":""},{"n":"アラカシ","f":"ブナ科","t":"常緑広葉樹","fl":"4～5","h":"7～10","su":"〇～△","w":"中","c":"〇","dw":"〇～△","al":"","p":"アブラムシ\nカイガラムシ\nイラガ","d":"メインツリーにも生垣にも古くから庭木として利用されます。濃い葉色と日本人がイメージする美しい樹形に近いことから重宝する庭木です。カシノキには数種類ありますが、他種と比較すると強いイメージとしっかりとしたイメージが強い木と言えます。","pr":"秋期","nt":"実はドングリの小型","td":"◎","so":"埴壌土"},{"n":"アンズ","f":"バラ科","t":"落葉広葉樹","fl":"4","h":"2～3","su":"","w":"","c":"◎","dw":"","al":"","p":"灰星病\n黒粒枯病\n胴枯病\n黒星病\n疫 病\nコスカシバ\nアブラムシ類\nナミハダニ\nシ ンクイムシ類\nカイガラムシ類\nアメリカシロヒトリ等","d":"ウメやスモモに似るがこれらよりも大きく、花数も多い。","pr":"花後(5月)、12月","nt":"","td":"△","so":""},{"n":"イスノキ","f":"イスノキ科","t":"常緑広葉樹","fl":"4","h":"15～18","su":"〇～△","w":"","c":"〇","dw":"〇","al":"","p":"スノキコムネ\nアブラムシ","d":"土壌を選ばず、移植は容易。マンサクの接ぎ台にも使用される。","pr":"6～7月","nt":"耐潮性に優れる。","td":"◎","so":""},{"n":"イチジク","f":"クワ科","t":"落葉広葉樹","fl":"7","h":"4～5","su":"","w":"","c":"△","dw":"","al":"黄","p":"カミキリムシ\nセンチュウ","d":"花が実の中に隠れて咲くという変わった仕組みになっているので、外からは見えない。実は内側に空洞のある袋状になっていて、内側に小さな花がたくさん並んでいる。花といっても花びらがなくて、花とは思えない姿をしている。","pr":"冬期","nt":"","td":"","so":""},{"n":"イチョウ","f":"イチョウ科","t":"落葉広葉樹","fl":"4","h":"15～18","su":"△","w":"","c":"〇","dw":"〇","al":"黄","p":"","d":"実のならない雄木の接木栽培品の利用が望まれる。巨大木になる。","pr":"冬期","nt":"","td":"△","so":""},{"n":"イトヒバ（ヒヨクヒバ）","f":"ヒノキ科","t":"常緑広葉樹","fl":"","h":"12～15","su":"〇～△","w":"","c":"〇","dw":"〇","al":"","p":"","d":"萌芽力があるので、強い刈り込みにも耐えますが、自然樹形も個性的で趣がある。","pr":"秋期（いつでも可）","nt":"","td":"△","so":""},{"n":"イヌシデ","f":"カバノキ科","t":"落葉広葉樹","fl":"4","h":"15～18","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"黄","p":"","d":"株立ちになりにくい。自然風の美しさを生かすため、通常は剪定を行わない。","pr":"冬","nt":"黄葉　秋","td":"〇","so":""},{"n":"イヌマキ","f":"マキ科","t":"常緑針葉樹","fl":"5～6","h":"5～7","su":"◎～〇","w":"中","c":"〇","dw":"◎～〇","al":"-","p":"マキシンハアブラムシ","d":"マキにも種類がありますが、本種はもっとも一般的であり、好きな形に仕立てることができるため、古くから重宝されてきました。イヌマキよりも短い葉のマキでラカンマキがあります。出雲地方ではコウヤマキと呼ばれることもありますが、実際のコウヤマキは葉が細く長いコウヤマキ科の樹種ですので、別物です。","pr":"秋期","nt":"","td":"〇","so":"全土"},{"n":"イロハモミジ","f":"カエデ科","t":"落葉広葉樹","fl":"5月","h":"10～12","su":"〇～△","w":"中","c":"〇","dw":"〇","al":"赤/黄","p":"アザミウマ\nアブラムシ\nカイガラムシ\nテッポウムシ\nうどん粉病","d":"モミジの中でも比較的小さな掌状の葉で非常に人気の高い樹木です。葉っぱの裂片（れっぺん）を「いろはにほへと」と数えたことから、イロハモミジという名がつきました。花が終わるころの7～8月に、プロペラのついた実ができます。イロハモミジを含め、モミジには園芸品種が豊富です。紅葉はもちろんですが、自然樹形の美しい樹形も見所です。","pr":"","nt":"","td":"△","so":"壌"},{"n":"ウツギ","f":"アジサイ科","t":"落葉広葉樹","fl":"5～6","h":"3～4","su":"〇～△","w":"","c":"◎","dw":"〇","al":"","p":"","d":"前年枝から伸びた枝先に花を付ける。春に強剪定を行うと花が見られない。","pr":"7月、11～2月","nt":"","td":"〇","so":""},{"n":"ウバメガシ","f":"ブナ科","t":"常緑広葉樹","fl":"4～5","h":"2～3","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"","p":"うどんこ病\nマイマイガ\nカシノナガキクイムシ","d":"材質が緻密で硬くなることから、焼き鳥、ウナギの蒲焼、炭焼焙煎コーヒーなどに使われる「備長炭」の材料になることで知られます。実は小さなドングリがつき、長さ１～２センチの楕円形で、翌年の秋に熟せば食用になります。非常に強く厳しい環境に耐え、刈込が効くことから生垣として使われます。","pr":"春、秋","nt":"","td":"◎","so":"全土"},{"n":"ウメ","f":"バラ科","t":"落葉広葉樹","fl":"1～2","h":"7～10","su":"〇～△","w":"","c":"◎","dw":"△","al":"","p":"アブラムシ\nコスカシバ","d":"白加賀、紅千鳥、寒紅梅、見驚、豊後梅などの品種が多く供給されている。","pr":"冬期（11～12月）","nt":"","td":"△","so":""},{"n":"ウメ　鹿児島紅梅","f":"バラ科","t":"落葉広葉樹","fl":"2～3月","h":"2～3","su":"◎～〇","w":"中","c":"◎","dw":"◎","al":"-","p":"アブラムシ\nカイガラムシ\n黒星病\nうどんこ病","d":"観賞価値が高い花を咲かせる「花ウメ」です。よって、実の収穫は期待できません。紅梅性のやや遅咲きの品種で、紅梅の代表格です。花は濃い紅色の中輪花で八重咲きです。細い枝の髄や葉柄も濃紅色となり艶やかな品種で庭木、鉢植えはもちろん、盆栽にも向きます。","pr":"11～12月","nt":"","td":"〇","so":"壌"},{"n":"ウメ（白加賀）","f":"バラ科","t":"落葉広葉樹","fl":"2～3月","h":"2～3","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"-","p":"黒星病\nアブラムシ\nコスカシバ\nカイガラムシ","d":"「しらかが」とか「しろかが」と呼びます。花も実も楽しめる古くから親しまれてきた優良品種です。江戸時代から栽培されている、日本で最も生産量の多い梅です。25～30gで種が小さく果肉厚く、梅干・梅酒・漬梅に向いています。南高梅と同様に実の粒は大きく、陽光に当たった面は熟すとともに紅を差してきます。結実も安定し、豊産性です。花粉少なく、受粉樹が必要です。梅にはクエン酸、リンゴ酸が豊富に含まれ、アルカリ食品として重宝します。ビタミンも豊富です。","pr":"","nt":"","td":"〇","so":"壌"},{"n":"ウメモドキ","f":"モチノキ科","t":"落葉広葉樹","fl":"6","h":"5～7","su":"〇～△","w":"中","c":"◎","dw":"〇～△","al":"赤/黄","p":"カイガラムシ\nアメリカシロヒトリ","d":"樹形や葉形がウメに似ているというのが名の由来ですが、ウメの仲間ではありません。赤い果実と風情のある樹形は非常に魅力的で人気が高い庭木です。落葉後にも果実が残るため、冬の彩や生け花としても重宝します。","pr":"12～2月（冬期）","nt":"","td":"△","so":"壌土"},{"n":"ウラジロガシ","f":"ブナ科","t":"常緑広葉樹","fl":"5～6","h":"7～10","su":"◎～△","w":"中","c":"△","dw":"〇","al":"","p":"アブラムシ\nカイガラムシ\nイラガ","d":"シラカシに似た木ですが、葉の裏側が白いためこの名がつきました。綺麗な樹形で育ち、メインツリーとして十分に見ごたえのある木です。大きくなるため広いスペースが必要です。風が吹くと葉の白い裏側が見え隠れし、さわやかなイメージを演出します。","pr":"秋期","nt":"","td":"△","so":"全土"},{"n":"エゴノキ","f":"エゴノキ科","t":"落葉広葉樹","fl":"5～6","h":"4～5","su":"◎～△","w":"中","c":"◎","dw":"〇","al":"赤/黄","p":"テッポウムシ\nイラガ\nミノムシ\nカイガラムシ\nシャクトリムシ\nうどんこ病","d":"細く伸びた枝に比較的小さい葉が茂り、柔らかいイメージを与える自然風の樹形です。幹が滑らかで赤色のため美しく、落葉期にも楽しめます。果実にはサボニンという有害な成分を含んでいるため、えぐみがあります（名の由来）。","pr":"冬期","nt":"実は毒がある","td":"△","so":"壌土"},{"n":"エゴノキ・ピンクチャイム","f":"エゴノキ科","t":"落葉広葉樹","fl":"5～6","h":"4～5","su":"◎～△","w":"中","c":"◎","dw":"〇","al":"赤/黄","p":"テッポウムシ\nイラガ\nミノムシ\nカイガラムシ\nシャクトリムシ\nうどんこ病","d":"細く伸びた枝に比較的小さい葉が茂り、柔らかいイメージを与える自然風の樹形です。幹が滑らかで赤色のため美しく、落葉期にも楽しめます。果実にはサボニンという有害な成分を含んでいるため、えぐみがあります（名の由来）。エゴノキは白花ですが、ピンクチャイムはピンクがかった花色が特徴です。","pr":"冬期","nt":"実は毒がある","td":"△","so":"壌土"},{"n":"エニシダ","f":"マメ科","t":"落葉広葉樹","fl":"4～6","h":"1～2","su":"〇～△","w":"","c":"◎","dw":"〇","al":"","p":"アブラムシ","d":"エニシダは、乾燥地で無駄に水分が奪われないよう葉は小さく、その分、緑色の枝でも光合成が行われます。耐寒性もあり、やせ地でも育ちますが、寿命は10年ほどです。黄色の花に赤色の入ったホホベニエニシダは本種の園芸品種です。別種に真っ白な花をつけるシロバナエニシダがありますが、こちらは落葉低木です。","pr":"6月","nt":"","td":"〇","so":"砂壌"},{"n":"エノキ","f":"ニレ科","t":"落葉広葉樹","fl":"4～5","h":"12～15","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"赤/黄","p":"アブラムシ\nハマキムシ\nマイマイガ\nメイガ\nタマバエ","d":"エノキの名の由来には諸説ありますが、「縁」に通じることから「縁結びの木」あるいは「縁切りの木」として使う俗信があります。縁を結ぶにはエノキに願をかけ、縁を切る場合は、人知れずそっとエノキの葉を食べると良いらしいです。榎の字のごとく夏には傘のように日陰を作る樹形をしています。実には甘みがあり、食べることができます。","pr":"冬","nt":"","td":"◎","so":"全土"},{"n":"エンジュ","f":"マメ科","t":"落葉広葉樹","fl":"7～8","h":"7～10","su":"◎～〇","w":"中","c":"◎","dw":"〇","al":"赤/黄","p":"ガンシュ病\nさび病","d":"古くから庭木や街路樹として植栽されています。樹皮は暗灰褐色で縦に割れ目が入るのが特徴です。花は淡い黄色の蝶型で、花の一つ一つは小さいですが、枝先にまとまって大きな円錐状に咲くため、遠目からは木の上に煙が立ち上がっているように見えます。秋には数珠のようにくびれた果実が枝先から垂れ下がります。材は器具、楽器、家具に使われ、灰色の樹皮を煎じたものは腰痛の薬に、根は「苦参（くじん）」という漢方薬になります。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"オウゴンマサキ","f":"ニシキギ科","t":"常緑広葉樹","fl":"6～7","h":"1～2","su":"◎～△","w":"中","c":"◎","dw":"◎～〇","al":"-","p":"うどんこ病\nカイガラムシ\nシャクトリムシ\nミノウスバ","d":"マサキは土地を選ばず耐陰性も強い為に、環境が悪くても生育できます。緑色のつやがある少し大きめの枝に楕円形の光沢がある革質の葉をつけます。若い葉は黄色になり成熟するにしたがって緑色になります。葉が観賞価値が高く庭木に利用されます。生垣にも使用でき刈り込むと枝葉が密になります。生け花材としても利用されます。葉に斑の入る種類もあります。","pr":"秋期（いつでも可）","nt":"","td":"◎","so":"全土"},{"n":"オウゴンモチノキ","f":"モチノキ科","t":"常緑広葉樹","fl":"4～5月","h":"5～7","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"","p":"カイガラムシ\nスス病","d":"新芽が黄色く目立つことから黄金と名がつきました。葉は夏に向けて徐々に緑色に変わります。古くから庭木の三大名木となされて人気のあるモチノキの園芸品種です。高木ですが、比較的成長が遅いので管理がしやすい木です。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"オウバイ","f":"モクセイ科","t":"落葉広葉樹","fl":"3","h":"1～2","su":"◎～〇","w":"","c":"◎","dw":"△","al":"","p":"アブラムシ","d":"春一番に黄色い花を咲かせ、迎春花と呼ばれることもある。","pr":"落葉期、6月","nt":"","td":"〇","so":""},{"n":"オオデマリ","f":"スイカズラ科","t":"落葉広葉樹","fl":"5～6","h":"3～4","su":"〇～△","w":"","c":"◎","dw":"△","al":"","p":"アブラムシ\nハマキムシ\nサンゴジュハムシ","d":"アジサイに似た大きな手まり状の白花が株を覆うように咲く。\n開花期間が長い。","pr":"","nt":"","td":"△","so":""},{"n":"オオヤマレンゲ","f":"モクレン科","t":"落葉広葉樹","fl":"","h":"2～3","su":"〇～△","w":"","c":"〇","dw":"△","al":"-","p":"テンポウムシ\nグンバイムシ","d":"日本、中国原産の落葉低木です。奈良県南部の大峰山に自生していて、ハスの花（蓮華）に似た白い花が咲くことからその名前が付いています。花も美しいですが、よい香りがします。","pr":"","nt":"","td":"△","so":"壌"},{"n":"オガタマノキ","f":"モクレン科","t":"常緑広葉樹","fl":"5","h":"15～18","su":"〇～△","w":"","c":"△","dw":"△","al":"","p":"カイガラムシ","d":"暖地を好み、耐寒性は弱い。\n神社境内で神木や縁起木として植栽されることが多い。","pr":"花後","nt":"","td":"〇","so":""},{"n":"オトコヨウゾメ","f":"スイカズラ科","t":"落葉広葉樹","fl":"5～6月","h":"1～3","su":"△","w":"","c":"〇","dw":"△","al":"赤/黄","p":"アブラムシ","d":"本州から九州の雑木林に見られるガマズミの仲間です。やや視界が開けた場所に生えていることが多く、存在は地味だが、花、紅葉、赤い実と観賞価値が高いです。秋に熟する赤い実はいつまでも木にぶらさがっています。収穫すればおいしい果実酒となります。名前の語源ははっきりしません。","pr":"","nt":"","td":"△","so":"埴壌"},{"n":"オトメツバキ","f":"ツバキ科","t":"常緑広葉樹","fl":"3～5","h":"3～4","su":"◎～△","w":"中","c":"〇","dw":"〇","al":"","p":"チャドクガ","d":"ピンクの芸術的な花が人気のツバキです。春近くに咲きます。赤いツバキの中にピンクが混じるとより目立ちます。葉も艶があり存在感のある庭木です。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"オリーブ","f":"モクセイ科","t":"常緑広葉樹","fl":"5～7","h":"2～3","su":"◎","w":"中","c":"△","dw":"〇","al":"","p":"テッポウムシ\nハマキムシ\nスズメガ\nコガネムシ","d":"「平和の象徴」としてハトが葉を口にくわえているデザインをラッキーモチーフなどで見たことがあるかもしれませんが、あの葉はオリーブです。「平和のシンボル」とされるのは「旧約聖書」のノアの箱舟のエピソードに由来します。オリーブは萌芽力にも優れ、樹齢もとても長く、地中海沿岸地域では1000年を超える老木が今だに実をつけるそうです。地中海のイメージを庭に取り込める庭木として人気です。","pr":"冬期","nt":"同株","td":"〇","so":"壌"},{"n":"オロシマチク","f":"イネ科","t":"竹笹類","fl":"","h":"","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"","p":"","d":"竹類の中でも最も小さな笹で高さ20～40cmほどしかないのが特徴\n・刈込みに強く、地下茎をよく分岐するので、深く刈り込めば芝生のように地面を覆います。日当たりが悪い場所でも良く育ちます。4月上旬に刈り取りを行なうと、葉が小さくなり、緻密で美しい地被状態を維持でき、芝生代わりのグランドカバーとしても利用される","pr":"","nt":"","td":"","so":"壌"},{"n":"カイズカイブキ","f":"ヒノキ科","t":"常緑針葉樹","fl":"","h":"7～10","su":"◎～〇","w":"","c":"〇","dw":"〇～△","al":"","p":"","d":"刃物で切り込むと切り口が茶色に変色する。","pr":"秋","nt":"赤星病の中間宿主。","td":"◎","so":""},{"n":"カイドウ","f":"バラ科","t":"落葉広葉樹","fl":"4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"11月","nt":"","td":"","so":""},{"n":"カキ","f":"カキノキ科","t":"落葉広葉樹","fl":"5","h":"12～15","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬","nt":"","td":"","so":""},{"n":"カクレミノ","f":"ウコギ科","t":"常緑広葉樹","fl":"７～8","h":"2～3","su":"〇～△","w":"中","c":"△","dw":"△","al":"","p":"カイガラムシ\nテッポウムシ\nすす病","d":"古くから日本の庭園や寺社に親しまれてきた、「陰の美」を象徴する常緑樹。最大の魅力は、その名の由来にもなった「雨具の蓑（みの）」を思わせる独特な葉の形にあります。若木の頃は3～5つに深く切れ込んだ個性的な形をしていますが、生長して成木になると丸みを帯びた卵形へと変化していくという、一木の中で多様な葉の表情を楽しめるのが大きな特長です。非常に耐陰性が強く、他の樹木が育ちにくい日陰や建物の裏手でも、ツヤのある深い緑の葉を茂らせてくれます。生長が比較的緩やかで、横に広がらずにスッと直立する樹形を保ちやすいため、狭い場所の目隠しやモダンな和風住宅のアクセントとして非常に優秀です。","pr":"冬","nt":"","td":"◎","so":"砂壌"},{"n":"カツラ","f":"カツラ科","t":"落葉広葉樹","fl":"4～5","h":"15～18","su":"〇","w":"","c":"◎","dw":"〇","al":"赤","p":"カイガラムシ\nテッポウムシ\nイラガ","d":"カツラは、ハート形のかわいい新緑と、秋の鮮やかな黄葉、そして落葉時に漂う甘い香り（キャラメルや綿菓子のような）が魅力の落葉高木で、日本の庭木として人気です。高木になるため広いスペースが必要ですが、日陰や乾燥にも比較的強く（水切れ注意）、病害虫にも強いため育てやすく、自然樹形が美しいのが特徴で、シンボルツリーや街路樹にも適していると言われますが、出雲では西風及び西日が直接あたる場所は生育が難しいです。","pr":"冬期","nt":"黄葉","td":"〇","so":""},{"n":"カナメモチ","f":"バラ科","t":"常緑広葉樹","fl":"5～6月","h":"7～10","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5～6月、9月","nt":"","td":"","so":""},{"n":"ガマズミ","f":"レンプクソウ科","t":"落葉広葉樹","fl":"5～6","h":"1～2","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"赤","p":"","d":"ガマズミという名の由来には諸説あるが、「ガマ」は材を農具の柄（鎌柄）に使ったこと、あるいは葉の形がカメの甲羅に似ること、「ズミ」は果実が酸っぱいこと（酸実）、あるいは果実を衣類の染料（すり染め）に使ったことによるとされます。丈夫な性質を持ち、土質を選ばずに育ちますが、入手はやや難しいです。秋以降の果実は食べられ、ワイン色が美しい果実酒になります。","pr":"6月","nt":"","td":"△","so":""},{"n":"カラタネオガタマ","f":"モクレン科","t":"常緑広葉樹","fl":"4～6","h":"0.5～1.0","su":"◎","w":"","c":"△","dw":"〇","al":"","p":"","d":"花言葉は甘い誘惑で、5月頃に咲く花からは、花言葉どおりのような、\nバナナに似た独特の甘い香りがします。 そのため、 “バナナツリー”\nとも呼ばれています。","pr":"6月","nt":"","td":"〇","so":""},{"n":"カリン","f":"バラ科","t":"落葉広葉樹","fl":"4～5","h":"7～10","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"中国原産の落葉性高木で日本全国で広く植栽されている。 カリンは、落葉性の高木で高さが８メートルくらいにもなり、棘（とげ）状の小枝があって樹皮は緑褐色で鱗片状にはがれて雲紋状になります。","pr":"冬期","nt":"","td":"〇","so":""},{"n":"カルミア","f":"ツツジ科","t":"常緑広葉樹","fl":"5","h":"4～5","su":"〇","w":"","c":"〇","dw":"〇～△","al":"","p":"グンバイムシ類、\nアブラムシ、\nハマキムシ","d":"","pr":"6月、10月","nt":"葉に麻酔性の有毒を含む","td":"〇","so":""},{"n":"カンツバキ","f":"ツバキ科","t":"常緑広葉樹","fl":"11～2","h":"0.5～1.0","su":"◎～△","w":"中","c":"◎","dw":"△","al":"-","p":"チャドクガ","d":"花の少ない冬期に赤い綺麗な花を咲かせます。色の濃い艶のある常緑の葉も非常に綺麗です。刈込んで形を整えることもでき、場所により使いやすい庭木です。また、非常に日陰の場所でも育ちますので、中庭などにも適します。","pr":"3～4月","nt":"害虫としてチャドクガが発生することがあります。チャドクガは毒を持ちますので、葉に食害痕がある場合は近づかないように気をつけます。","td":"〇","so":"埴壌"},{"n":"カンノンチク","f":"ヤシ科","t":"竹笹類","fl":"","h":"2～3","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"","nt":"","td":"","so":""},{"n":"キチジョウソウ","f":"ユリ科","t":"常緑多年草","fl":"9～12月","h":"","su":"〇～△","w":"中","c":"◎","dw":"〇","al":"","p":"ほとんどない","d":"","pr":"","nt":"","td":"△","so":"全土"},{"n":"キャラボク","f":"イチイ科","t":"常緑針葉樹","fl":"3～5","h":"3～4","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"雌雄別株。雄花は淡黄色。雌花には緑色の鱗片に包まれた胚珠が\n1個ある。種子は直径3〜4mmの球形で、花のあと肥大して杯状にな\nった仮種皮に包まれる。秋に種子が熟す頃には仮種皮は紅色になる\n。仮種皮は甘くて食べられる","pr":"11～3月（冬期）","nt":"種子9～10月","td":"〇","so":""},{"n":"キョウチクトウ","f":"キョウチクトウ科","t":"常緑広葉樹","fl":"6～9","h":"2～3","su":"◎","w":"中","c":"◎","dw":"〇","al":"","p":"カイガラムシ\nアブラムシ","d":"夏の代表的な花木として親しまれています。長期間花を咲かせます。花の色にはピンク、白、黄色などがあり、一重だけではなく、八重咲きの品種もあります。葉が竹に、花が桃に似ていることから夾竹桃と名付けられました。","pr":"10月","nt":"","td":"〇","so":"全土"},{"n":"キングサリ","f":"マメ科","t":"落葉広葉樹","fl":"5～6","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月","nt":"","td":"","so":""},{"n":"キンシバイ","f":"オトギリソウ科","t":"落葉広葉樹","fl":"6～7","h":"0.5～1.0","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"ビヨウヤナギとキンシバイの違い両者はとてもよく似ているが、ビヨウヤナギの方が葉も花も大きい。また雄しべの数もビヨウヤナギの方が圧倒的に多く、長さも花弁から飛び出すほどあるため、見分けがつきやすい。","pr":"9～10月","nt":"","td":"〇","so":""},{"n":"ギンバイカ","f":"フトモモ科","t":"常緑広葉樹","fl":"5～6月","h":"1～2","su":"◎～〇","w":"","c":"△","dw":"〇","al":"","p":"カイガラムシ\nさび病","d":"銀梅花と書きます。芳香があるかわいい白い花を枝先に開花さます。ハーブとしてマートルの名前でもよく知られています。葉には油腺があり、葉をたたいたりもむことでフルーティーな芳香が放たれます。秋に黒っぽく熟す果実も芳香と甘みがあり食べることができます。刈り込みにも耐えるため、生け垣やトピアリーの素材にも適しているので、庭木としての利用価値も高い樹種ですが、寒冷地では防寒が必要です。","pr":"","nt":"","td":"△","so":"全土"},{"n":"ギンマサキ","f":"ニシキギ科","t":"常緑広葉樹","fl":"6～7","h":"1～2","su":"◎～△","w":"中","c":"◎","dw":"◎～〇","al":"-","p":"うどんこ病\nカイガラムシ\nシャクトリムシ\nミノウスバ","d":"マサキの園芸品種で、葉の外周に乳白色の斑が入り、内側のやや薄い緑色の部分に乳白色を帯びた薄い緑色がマーブル模様のように入ります。非常に強い上、葉が明るく綺麗なため人気の高い庭木です。","pr":"秋期（いつでも可）","nt":"","td":"◎","so":"全土"},{"n":"キンメツゲ","f":"ツゲ科","t":"","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"秋期","nt":"","td":"","so":""},{"n":"キンモクセイ","f":"モクセイ科","t":"常緑広葉樹","fl":"9～10","h":"3～4","su":"◎","w":"中","c":"△","dw":"◎～〇","al":"-","p":"カイガラム\nヘリグロテントウノミハムシ\nマエアカスカシノメイガ\nアオバハゴロモ\nイボタガ\nハマキムシ\n先葉枯病\n炭疽病\nうどんこ病\nハダニ\nアブラムシ\n褐斑病","d":"ジンチョウゲ、クチナシと並ぶ「三香木」のひとつです。芳香剤としてもおなじみの強い香りを放つ花が特長で、遠くまで香りが届くことから古くは「千里香」とも呼ばれていました。キンモクセイ(金木犀）のオレンジ色の小花をいっぱいにつけた姿は、日差しを受けると名前の通り金色に輝いて見え、秋の風物詩となっています。","pr":"11～12月","nt":"","td":"△","so":"全土"},{"n":"ギンモクセイ","f":"モクセイ科","t":"","fl":"9～10","h":"7～10","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"花後","nt":"","td":"","so":""},{"n":"クサツゲ","f":"ツゲ科","t":"落葉広葉樹","fl":"","h":"7～10","su":"◎","w":"","c":"△","dw":"〇","al":"","p":"","d":"","pr":"秋","nt":"紅葉　秋","td":"〇","so":""},{"n":"クスノキ","f":"クスノキ科","t":"常緑広葉樹","fl":"5～6","h":"15～18","su":"◎～〇","w":"","c":"◎","dw":"◎～〇","al":"","p":"グンバイムシ\nアゲハ\nメイガ\nモザイク病","d":"幹周囲10m以上の巨樹になる個体も珍しくないほど大きくなる木として有名です。樹形はこんもりとした形をなします。その綺麗な樹形で公園ではシンブルツリーとしても使われています。果実は鳥が食べてが、人間の食用には適しません。各部全体から樟脳の香りがします。樟脳とはクスノキの枝葉を蒸留して得られる無色透明の固体のことで、防虫剤や医薬品等に使用されます。","pr":"秋期（いつでも可）","nt":"","td":"〇","so":"全土"},{"n":"クチナシ","f":"アカネ科","t":"常緑広葉樹","fl":"5～7","h":"0.5～1.0","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"花はジャスミンに似た甘い香りを放ち、キンモクセイやジンチョウゲと\n共に三大芳香木とされ、自生地以外でも庭木や切り花に使われる。\n日本のほか中国やインドシナに自生する。","pr":"冬期","nt":"実に薬効がある。","td":"〇","so":""},{"n":"クロガネモチ","f":"モチノキ科","t":"常緑広葉樹","fl":"5～6","h":"12～15","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"「苦労がなく金持ち」に通じるネーミングから縁起木として知られる。\nモチノキの仲間で、若い枝や葉柄が黒紫色であることや、葉が乾くと\n鉄色になることからクロガネモチと名付けられた\n（鉄のことをクロガネという）。","pr":"3月下旬、11＝","nt":"","td":"〇","so":""},{"n":"クロモジ","f":"クスノキ科","t":"落葉広葉樹","fl":"3～4","h":"4～5","su":"〇","w":"中","c":"◎","dw":"〇","al":"黄","p":"カイガラムシ","d":"ダークグリーンの樹皮にできる黒い斑点を文字に見立てて「黒文字」と名付けられたといわれます。樹皮や葉にはテルペネオールやリモネンという芳香成分が含まれ、柑橘系に似た特有の香りがあります。樹皮を残したクロモジの材で作られた爪楊枝は高級品として茶席の和菓子などに添えられます。","pr":"秋期","nt":"","td":"△","so":"壌"},{"n":"クワ","f":"クワ科","t":"","fl":"4～5","h":"12～15","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"1～2月","nt":"","td":"","so":""},{"n":"ゲッケイジュ","f":"クスノキ科","t":"常緑広葉樹","fl":"4～5","h":"2～3","su":"◎","w":"少","c":"〇","dw":"◎","al":"-","p":"スス病\nテッポウムシ\nハマキムシ\n褐色円班病","d":"地中海沿岸を原産地とする常緑樹で、明治３９年にフランスから渡来しました。独特の香りを持つ枝葉が香辛料として料理に使われることから、クッキングハーブなどとも呼ばれます。古代ギリシャでは競技の勝者に月桂樹の葉で作った冠（月桂冠）を贈る習慣がありました。","pr":"秋期","nt":"","td":"◎","so":"砂壌"},{"n":"ケヤキ","f":"ニレ科","t":"落葉広葉樹","fl":"4","h":"15～18","su":"◎","w":"多","c":"◎","dw":"△","al":"赤/黄","p":"アブラムシ\n褐斑病","d":"箒を逆さまにしたような綺麗な樹形で、街路樹や公園など日本中に植えられている木です。枝がきれいに扇状に伸びる姿は、落葉期での非常に美しいです。また、秋の紅葉も見ることができます。語源は「際立って目立つ」「美しい」といった意味の「けやけし」に由来し、「けやけき木」の略と考えられています。","pr":"2～3月","nt":"黄紅葉","td":"〇","so":"湿壌"},{"n":"コウヤマキ","f":"スギ科","t":"常緑針葉樹","fl":"","h":"15～18","su":"◎～〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"コウヤマキ科には本種しかなく「一科一属一種」の珍しい植物であり、日本にしかない「～科」はコウヤマキ科のみである。庭木としては\n人工的に繁殖されたものが多数出回っており、公園や寺社仏閣等で\n普通に見られる。","pr":"3～4月","nt":"","td":"〇","so":""},{"n":"コウライシバ","f":"イネ科","t":"芝類","fl":"","h":"～0.1","su":"◎","w":"","c":"◎","dw":"◎","al":"","p":"・さび病\n・ブラウンパッチ\n・コガネムシ","d":"芝生には大きく分けて日本芝と西洋芝があり、日本芝はその名の通り高温多湿に適した日本の環境に合った性質を持つ芝です。日本芝の代表ともいえるコウライシバは、日本では東北以南で最も多く使用され日本の風土にあった芝です。葉の幅は野芝よりも細く、刈込みによって密度も細かく、見た目にも綺麗な芝生になります。","pr":"","nt":"","td":"◎","so":"砂壌"},{"n":"コデマリ","f":"バラ科","t":"落葉広葉樹","fl":"4～5月","h":"1～2","su":"◎","w":"中","c":"〇","dw":"〇","al":"赤/黄","p":"アザミウマ\nアブラムシ\nカイガラムシ\nうどんこ病","d":"細い枝や葉が見えなくなるほど白い多数の花を咲かせ、枝垂れる姿がとても見事で、庭木や切り花として利用される、春を代表する花木です。同じ仲間のユキヤナギよりも遅く、赤褐色の新梢が伸びたあとに開花します。古く中国から渡来し、江戸時代初期から観賞用に栽培されてきました。和名は花の集まり（花序）を、小型の手まりに見立てたものです。","pr":"6月","nt":"","td":"〇","so":"全土"},{"n":"コナラ","f":"ブナ科","t":"落葉広葉樹","fl":"4～5月","h":"7～10","su":"◎","w":"","c":"◎","dw":"〇","al":"赤/黄","p":"カシノナガキクイムシ","d":"雑木林の代表樹で、樹液にはカブトムシやクワガタが集まります。材は木炭の原料や、シイタケの原木に使われます。ドングリに実がつく木としても有名です。かつて東北地方の山村では、コナラのドングリはミズナラのドングリと並んで重要な食料でした。秋にはオレンジ色に紅葉しますが、その後褐色に変化し、しばらく落葉せず葉が残ります。","pr":"","nt":"","td":"△","so":"壌"},{"n":"コニファー（ヒノキ）","f":"ヒノキ科","t":"常緑針葉樹","fl":"","h":"15～18","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"冬、7～8月","nt":"","td":"〇","so":""},{"n":"コノテヒバ（コノテガシワ）","f":"ヒバ科","t":"常緑針葉樹","fl":"3～4","h":"15～18","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬、7～8月","nt":"","td":"","so":""},{"n":"コハウチワカエデ","f":"ムクロジ科","t":"落葉広葉樹","fl":"5～6","h":"4～5","su":"◎～〇","w":"中","c":"◎","dw":"〇","al":"赤/黄","p":"テンポウムシ","d":"天狗がもっている団扇に似た形の葉を持つ、紅葉がきれいな庭木です。ハウチワカエデよりも一回り葉が小さいのでコハウチワカエデと呼ばれます。イロハモミジよりも葉の切れ込みの数が多く、新緑にはきれいなライム色の葉が茂ります。紅葉の時期には日当たりによって赤、黄色、緑と一つの枝に多様な色の葉がつき、目を楽しませてくれます。洋風や雑木風のお庭にもよく似合い、シンボルツリーにもおすすめです。","pr":"12～2月","nt":"紅葉","td":"△","so":"壌"},{"n":"コバノズイナ","f":"ズイナ科","t":"落葉広葉樹","fl":"5～6月","h":"1～2","su":"◎～△","w":"","c":"◎","dw":"〇","al":"赤/黄","p":"カイガラムシ","d":"ズイナ（髄菜)の名前のは、枝の髄が行灯の灯心に、若葉が食用にされたことから来ています。枝先に総状花序（柄のある花が花茎に均等につく）を出し、白い小さな花を穂のようにつます。 花はよい香りがします。","pr":"","nt":"","td":"△","so":""},{"n":"コブシ、モクレン","f":"モクレン科","t":"落葉広葉樹","fl":"3～4","h":"12～15","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"4月または11月以降","nt":"","td":"","so":""},{"n":"コムラサキシキブ","f":"シソ科","t":"落葉広葉樹","fl":"6～7月","h":"0.5～1.0","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"","p":"カイガラムシ","d":"同属のムラサキシキブとともに平安時代の作家、紫式部にちなんで名付けられた。ムラサキシキブは樹高が３ｍになる「木」という印象だが、本種は樹高が１．５ｍ程度に収まり、いわゆる「下草」として、より広く親しまれる。一般的には誤って本種をムラサキシキブと呼んでいることが多い。\t\n・葉の鋸歯が上半部にしかないことや、花序の柄が葉腋より上につく(実が葉に隠れない)ことでムラサキシキブと区別できる。\n・ムラサキシキブより実つきはよい。","pr":"","nt":"","td":"△","so":"埴壌"},{"n":"ザイフリボク","f":"バラ科","t":"","fl":"4～5","h":"7～10","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月","nt":"","td":"","so":""},{"n":"サクラ類","f":"バラ科","t":"","fl":"3～4","h":"5～7","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"4月","nt":"紅葉","td":"","so":""},{"n":"ザクロ","f":"ザクロ科","t":"","fl":"5～6","h":"5～7","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"1～3月（冬期）","nt":"","td":"","so":""},{"n":"サザンカ","f":"ツバキ科","t":"常緑広葉樹","fl":"10～1","h":"2～3","su":"◎～〇","w":"","c":"〇","dw":"〇","al":"","p":"チャドクガ\nカイガラムシ","d":"サザンカには３００以上の園芸品種があり、晩秋～冬に咲く花を観賞するため、庭木や鉢植えに使われることが多いです。上手に管理すれば花で覆われた垣根を作ることができ、古くから人気が高いです。サザンカという名前は、ツバキの漢名であるサンサカ（山茶花）が転訛したもの。当初は「さんざか」と呼ばれていたましたが、園芸品種が作られるようになった江戸時代初期以降は「サザンカ」として定着しました。","pr":"2～4月","nt":"","td":"〇","so":"埴壌"},{"n":"サツキ","f":"ツツジ科","t":"常緑広葉樹","fl":"4～6","h":"1～2","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"6月","nt":"","td":"〇","so":""},{"n":"サルココッカ","f":"ツゲ科","t":"常緑広葉樹","fl":"3～4月","h":"～0.5","su":"〇～△","w":"","c":"〇","dw":"〇","al":"","p":"","d":"丈夫な性質で日陰や病害虫に強いため人気のある低木です。主に地被用途に使われます。樹形は株立ち状になり、あまり背が高くなりません。春に咲く芳香のある小さな白花と秋に赤紫や黒実はをつけますが、普段はツヤのある葉を主に楽しみます。葉は先の尖った楕円形で濃緑、やや厚みがあって強い光沢をはなちます。とても使い勝手のよい樹木で、ビルの陰になる植え込みなど実用的な緑化にもよく用いられています","pr":"","nt":"","td":"△","so":"埴壌"},{"n":"サルスベリ","f":"ミソハギ科","t":"落葉広葉樹","fl":"6～9","h":"5～7","su":"◎～〇","w":"中","c":"◎","dw":"〇","al":"赤/黄","p":"うどんこ病\n褐斑病\nカイガラムシ\nアブラムシ","d":"木登り上手のサルですら、すべって登ることができないほど、樹皮がツルツルとなめらかなのが名前の由来です。中国原産で、日本では古くから百日紅（ひゃくじつこう）と呼ばれていました。これは、夏じゅう赤い花が咲き続けることに因みます。花色は数種あります。","pr":"冬期","nt":"","td":"〇","so":"全土"},{"n":"サンゴジュ","f":"スイカズラ科","t":"常緑広葉樹","fl":"5～6","h":"7～10","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"秋期","nt":"","td":"◎","so":""},{"n":"サンザシ","f":"バラ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5月","nt":"","td":"","so":""},{"n":"サンシュユ","f":"ミズキ科","t":"落葉広葉樹","fl":"3～4","h":"4～5","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"黄","p":"・イラガ","d":"春に咲く黄色い花や、秋にできる赤い果実を観賞するため、江戸時代から庭木として各地に植栽されます。漢字表記は山のグミを意味する「山茱萸」であり漢名に由来します。日本ではこれを音読みしてサンシュユとしました。漢方では果実を山茱萸（サンシュユ）と呼び、滋養・強壮・強精・収れん・止血などに効果があるとされ八味地黄丸などに処方されています。\nまた滋養強壮や疲労回復などにこの実をホワイトリカーに漬け健康酒としても用いられています。","pr":"花後","nt":"","td":"△","so":"壌"},{"n":"サンショウ","f":"ミカン科","t":"","fl":"3～4","h":"4～5","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬","nt":"","td":"","so":""},{"n":"シイ（スダジイ）","f":"ブナ科","t":"常緑広葉樹","fl":"5～6","h":"15～18","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"秋期","nt":"","td":"〇","so":""},{"n":"シダレウメ","f":"バラ科","t":"","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6～7月","nt":"","td":"","so":""},{"n":"シマトネリコ","f":"モクセイ科","t":"常緑広葉樹","fl":"5～7","h":"5～7","su":"◎～〇","w":"","c":"△","dw":"〇","al":"","p":"・すす病\n・炭疽病\n・ハマキムシ\n・アブラムシ","d":"常緑樹の中でも葉が小さく涼しげな樹形のイメージを抱く数少ない庭木の一つです。さわやかなイメージが非常に人気で、室内用の観葉植物としても使われます。性質は半落葉性で、寒さが厳しいと落葉します。よって、冬季の西風は避ける方がよいでしょう。日照には幅広く対応でき、室内の明かりでも育てることができます。","pr":"秋期","nt":"","td":"△","so":"壌"},{"n":"シモツケ","f":"バラ科","t":"落葉広葉樹","fl":"6～7","h":"0.5～1.0","su":"◎～〇","w":"","c":"◎","dw":"〇～△","al":"赤/黄","p":"","d":"シモツケは日本、朝鮮半島、中国に分布する落葉低木です。和名は下野（しもつけ）の国（現在の栃木県）にちなみます。育てやすくて大きくならず、観賞期間もとても長い、特に初心者におすすめの花木です。初夏に、紅色の小さな花を枝先にたくさんつけます。花色や葉色が変化した園芸品種が多数あり、花のない時期でも、春から秋まで葉色の変化を楽しむことができます。","pr":"7月","nt":"","td":"〇","so":"壌"},{"n":"シャクナゲ類","f":"ツツジ科","t":"常緑広葉樹","fl":"5～6","h":"2～3","su":"◎～〇","w":"","c":"〇","dw":"〇～△","al":"","p":"","d":"","pr":"6月","nt":"","td":"△","so":""},{"n":"シャシャンボ","f":"ツツジ科","t":"常緑広葉樹","fl":"7","h":"1～2","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"","p":"アブラムシ","d":"小さな果実が並んで実る様を「小小坊」と表現して名付けられました。ブル－べリーはシャシャンボの仲間で、北アメリカの野生種を改良したものです。シャシャンボの果実はブル－べリーほど大きくはないですが、よく熟したものはけっこう美味しいです。","pr":"","nt":"","td":"△","so":"壌"},{"n":"ジャノメエリカ","f":"ツツジ科","t":"常緑広葉樹","fl":"12～4","h":"1～2","su":"","w":"","c":"◎","dw":"△","al":"","p":"アブラムシ\nカイガラムシ","d":"開花期は、種類によりそれぞれ異なり、春咲き種、夏～秋咲き種、\n冬咲き種、不定期咲き種に大別さる。","pr":"4～5月","nt":"","td":"","so":""},{"n":"ジャノメエリカ","f":"ツツジ科","t":"","fl":"2～3","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5～6月","nt":"","td":"","so":""},{"n":"シャリンバイ","f":"バラ科","t":"常緑広葉樹","fl":"3～5","h":"1～2","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"花がウメに似ていて、葉が枝先に車輪状に集まることから名の由来が来ている。白花の花言葉は清らかな白い花を咲かせることから「純真」、桃花の花言葉はピンク色の花が醸し出すロマンチックな雰囲気で「愛の告白」。花にはすっきとして爽やかな芳香がある。\n種類としては、「ベニバナシャリンバイ（ほんのりとピンク色をした花が咲く品種）\n「マルバシャリンバイ（葉が丸く、小枝が密生し、背丈が低い） \n「ヒメシャリンバイ（葉が小型で生長が遅い）","pr":"5月","nt":"","td":"◎","so":"全土"},{"n":"ジューンベリー（アメリカザイフリボク）","f":"バラ科","t":"落葉広葉樹","fl":"4～5","h":"4～5","su":"〇～△","w":"中","c":"◎","dw":"〇～△","al":"赤/黄","p":"カイガラムシ\nアブラムシ\nテッポウムシ","d":"６月ごろに果実を収穫できることから、ジューンベリーといいます。赤黒く熟す実は甘みがあり、ジャム、果実酒等に利用されます。鳥も好んで食べにきます。花も実も紅葉も楽しめることから、一年中楽しめる庭木です。","pr":"6月","nt":"","td":"△","so":"壌土"},{"n":"シュロ","f":"ヤシ科","t":"","fl":"5～6","h":"5～7","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月","nt":"","td":"","so":""},{"n":"シラカシ","f":"ブナ科","t":"常緑広葉樹","fl":"4～5","h":"7～10","su":"〇～△","w":"中","c":"〇","dw":"〇","al":"","p":"アブラムシ\nカイガラムシ\nイラガ","d":"メインツリーにも生垣にも古くから庭木として利用されます。濃い葉色と日本人がイメージする美しい樹形に近いことから重宝する庭木です。カシノキには数種類ありますが、他種と比較すると優しいイメージが強い木と言えます。","pr":"秋期","nt":"実はドングリの小型","td":"〇","so":"埴壌土"},{"n":"シラカバ","f":"カバノキ科","t":"","fl":"4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"3月（できるだけ剪定は避ける）","nt":"","td":"","so":""},{"n":"シロヤマブキ","f":"バラ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"1～2月","nt":"","td":"","so":""},{"n":"ジンチョウゲ","f":"ジンチョウゲ科","t":"落葉広葉樹","fl":"3～4","h":"0.5～1.0","su":"〇～△","w":"中","c":"〇","dw":"〇","al":"","p":"白紋羽病、\nウイルス病、\nアブラムシ、\nハマキムシ","d":"香りのよい花を早春に咲かせる常緑の花木です。花弁のように見える部分は萼が花弁状に変化したもので、本来の花弁ではありません。\n室町時代以前に中国から日本に渡来したといわれています。日本で栽培される株はほとんど結実しません。移植が難しいので、場所をよく選んでから植えつけます。","pr":"花後","nt":"","td":"△","so":"砂壌"},{"n":"スイカズラ","f":"スイカズラ科","t":"","fl":"5～6","h":"","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"6月","nt":"","td":"◎","so":""},{"n":"スギ","f":"ヒノキ科","t":"常緑針葉樹","fl":"2～4","h":"15～18","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"秋期","nt":"","td":"〇","so":""},{"n":"スモークツリー","f":"ウルシ科","t":"","fl":"5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5月","nt":"","td":"","so":""},{"n":"スモモ類","f":"バラ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5月","nt":"","td":"","so":""},{"n":"セイヨウベニカナメモチ（レッドロビン）","f":"バラ科","t":"常緑広葉樹","fl":"5～6","h":"3～4","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"ハマキムシ\nアプラムシ\nイラガ\n褐斑病","d":"新芽が赤くて鮮やかなことから生垣として長い間愛されてきました。萌芽力も強くて密になりやすいので、刈込に適する庭木です。西洋とつくのは、別にカナメモチがあるからです。カナメモチは見た目は非常に似ていますが、生育の強さは西洋の方が強いです。別名のレッドロビンはレッドロビンは「赤いコマドリ」の意味です。","pr":"秋期（いつでも可）","nt":"","td":"△","so":"全土"},{"n":"センリョウ","f":"センリョウ科","t":"常緑広葉樹","fl":"7月","h":"～0.5","su":"△","w":"中","c":"△","dw":"〇","al":"","p":"病害はほとんど見られませんが、根や茎が黒変し、腐って枯死する立枯病に侵されることがあります。罹病株から土壌を伝って感染するので、株を抜いて廃棄し、病気が発生した場所には植えないようにします。","d":"花の少ない冬に、美しい果実をつけるセンリョウは、正月の縁起物として人気の高い植物です。センリョウは千両の意味で、マンリョウ（万両、）や、ヒャクリョウ（百両、）とも称されるカラタチバナと同じ仲間と思われがちですが、センリョウはセンリョウ科の常緑低木で、ヒトリシズカやフタリシズカなどと同じ仲間です。センリョウの品種には、黄色の実をつけるキミノセンリョウや斑入りの品種があります。日本の暖地に自生するので栽培は容易で、極端な乾燥に注意すれば、実もよくつきます。","pr":"秋期","nt":"","td":"△","so":"砂壌"},{"n":"ソテツ","f":"ソテツ科","t":"","fl":"6～8","h":"4～5","su":"◎","w":"","c":"△","dw":"〇～△","al":"","p":"","d":"","pr":"","nt":"","td":"◎","so":""},{"n":"ソヨゴ","f":"モチノキ科","t":"常緑広葉樹","fl":"6～7","h":"2～3","su":"◎～〇","w":"中","c":"〇","dw":"〇","al":"","p":"ハマキムシ\n黒星病","d":"常緑樹としては軽めの樹形と小さめの葉から、雑木の庭に好んで使われる人気の樹木です。さらに赤い実も楽しめます。風に「そよぐ」ことからソヨゴと名がついたそうです。葉は全縁の小判型で、葉縁が波打ちます。初夏に長い柄の先に小さい白い花を咲かせ、その後に赤い実がつきます。樹皮はやや白っぽい灰色です。雌雄異株なので、実を楽しみたい場合は購入時に雌株かどうか確認が必要です","pr":"冬～早春","nt":"異株","td":"△","so":"全土"},{"n":"タイサンボク","f":"モクレン科","t":"","fl":"5～6","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"花後","nt":"","td":"","so":""},{"n":"ダイミョウチク","f":"イネ科","t":"竹笹類","fl":"","h":"5～7","su":"◎～△","w":"","c":"◎","dw":"◎","al":"","p":"テングス病\nさび病\n赤衣病\n紫紋羽病\nハダニ","d":"節と節の間が60〜80 cmと長く、剪定により節部に葉を密集させることができて美しいです。生垣や庭園竹とされます。梅雨時に出るタケノコ（筍）は皮色が紫をしており食用とされます。皮の紫色は成長して竹になっても節の部分で見られます。別名トウチク（唐竹）とも呼ばれます。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"タニウツギ","f":"スイカズラ科","t":"落葉広葉樹","fl":"5～6","h":"4～5","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"","nt":"","td":"〇","so":""},{"n":"タブノキ","f":"クスノキ科","t":"常緑広葉樹","fl":"4～6","h":"10～12","su":"◎～△","w":"","c":"◎","dw":"〇","al":"","p":"テッポウムシ\n白藻病","d":"葉芽は春になるとまるで別な生き物のようにダイナミックに展開しますが、特に早春はピンク色を帯びていて花のように見えます。本当の花が咲くのは４～６月頃です。直径５ミリほどの黄緑色の小さな花が円錐状に群がって咲くがあまり目立ちません。","pr":"2～3月、6～10月","nt":"","td":"◎","so":"全土"},{"n":"タマゴケ","f":"苔類","t":"","fl":"","h":"","su":"〇～△","w":"","c":"◎","dw":"〇","al":"","p":"","d":"胞子嚢（ほうしのう）の形が球状で、他のコケにはない愛らしさがあります。元気に育つとたくさん胞子嚢を付けてくれます。\n暑さと乾燥しすぎに弱いので、夏場の飼育は注意が必要です。","pr":"","nt":"","td":"","so":"壌"},{"n":"タマリュウ","f":"キジカクシ科","t":"常緑多年草","fl":"7～8月","h":"","su":"◎～△","w":"中","c":"◎","dw":"〇","al":"","p":"ほとんどない","d":"","pr":"","nt":"","td":"△","so":"全土"},{"n":"タラヨウ","f":"モチノキ科","t":"常緑広葉樹","fl":"4～5","h":"15～18","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"冬期","nt":"","td":"〇","so":""},{"n":"タラヨウ","f":"モチノキ科","t":"","fl":"","h":"15～18","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"","nt":"","td":"","so":""},{"n":"チャノキ","f":"ツバキ科","t":"常緑広葉樹","fl":"10～11","h":"1～2","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"チャドクガ","d":"","pr":"4月","nt":"","td":"〇","so":""},{"n":"チャボヒバ","f":"ヒノキ科","t":"常緑針葉樹","fl":"","h":"5～7","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"7月、秋期","nt":"","td":"〇","so":""},{"n":"チョウセンガヤ","f":"イヌガヤ科","t":"","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"秋期","nt":"","td":"","so":""},{"n":"ツゲ(イヌ、キンメ、マメ)","f":"ツゲ科","t":"","fl":"6～7","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"秋期","nt":"","td":"","so":""},{"n":"ツバキ　ワビスケ","f":"ツバキ科","t":"常緑広葉樹","fl":"11～4","h":"2～3","su":"◎～△","w":"中","c":"△","dw":"△","al":"-","p":"チャドクガ","d":"ツバキの品種の一つです。雄しべが退化し、一般のツバキに比べて花は小型で、開き切らずに筒状になるのが特徴です。葯が変形していて、受粉し難しいです。茶席には欠かせない花です。園芸品種があり、「白侘助」は11～３月、「紅侘助」は２～４月、「胡蝶侘助」は３～４月に花が咲きます。","pr":"","nt":"","td":"△","so":"埴壌"},{"n":"ツリバナ","f":"ニシキギ科","t":"落葉広葉樹","fl":"5月","h":"1～2","su":"△","w":"中","c":"◎","dw":"△","al":"赤/黄","p":"ほとんどつかない","d":"花や実がぶら下がってできることからツリバナと呼ばれます。新しい枝は緑色ですが、歳月を経るに従って紫がかった茶色となります。５月ごろに写真のような黄緑色の花を咲かせます。小さな花ですが、釣り下がる様子には話題性がある。秋にできる実は球形で直径１センチほどで、枝先にできます。朱色でよく目立つ上、時が経つと五つに割れ、内部がよく見えるようになります。形は違うもののマユミやニシキギに似ます。","pr":"","nt":"","td":"△","so":"全土"},{"n":"トウカエデ","f":"ムクロジ科","t":"落葉広葉樹","fl":"4～5月","h":"7～10","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"赤/黄","p":"イラガ\nカメムシ","d":"楓の種類で紅葉が綺麗な木です。非常に強健で場所を選ばず育ちます。紅葉の仲間としてはかなり背が高くなるほうです。幹は徐々に割れていき、剥がれ落ちるような特徴的な幹肌です。街路樹にもよく使われていて、シンボルツリーとしても見ごたえのある木です。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"ドウダンツツジ","f":"ツツジ科","t":"常緑広葉樹","fl":"4～5","h":"1～2","su":"◎","w":"中","c":"◎","dw":"◎","al":"赤/黄","p":"アブラムシ\nハマキムチ\nカイガラムシ\nテッポウムシ","d":"春に咲く白い壺形のかわいらしい小花と、秋の紅葉がすばらしい、落葉性の花木です。葉が出る前に開花します。低木ですが、長年かけて仕立てると見事な樹形になります。寄せ植えして刈込にもできます。特徴的な樹形を利用してアクセントに使うこともできます。","pr":"6月","nt":"紅葉","td":"△","so":"全土"},{"n":"トウネズミモチ・トリカラー","f":"モクセイ科","t":"常緑広葉樹","fl":"6月","h":"2～3","su":"◎～〇","w":"中","c":"◎","dw":"◎","al":"","p":"カイガラムシ\nスス病\n白藻病","d":"","pr":"","nt":"","td":"〇","so":"全土"},{"n":"トキワマンサク青葉","f":"マンサク科","t":"常緑広葉樹","fl":"4～5","h":"2～3","su":"◎～〇","w":"","c":"△","dw":"〇","al":"","p":"カイガラムシ","d":"トキワマンサクは、マンサク科トキワマンサク属に1種のみ知られている常緑樹です。しなやかな枝に卵形の小さな葉が優しく揺れる姿が人気です。花は細いリボンのような4枚の花弁があり、春の開花期には枝先に集まるように咲くため株全体が花に覆われ、遠くからでもその美しさが楽しめます。緑の葉に黄色みを帯びた白い花が輝くように映えます。園芸品種には葉に赤みを帯びるものや花色が赤いもの（上写真）もあり周囲の植物との組み合わせも、幅広く楽しめます。","pr":"6月","nt":"","td":"△","so":"砂"},{"n":"トキワマンサク赤葉","f":"マンサク科","t":"常緑広葉樹","fl":"4～5","h":"2～3","su":"◎～〇","w":"","c":"△","dw":"〇","al":"","p":"カイガラムシ","d":"トキワマンサクは、マンサク科トキワマンサク属に1種のみ知られている常緑樹です。しなやかな枝に卵形の小さな葉が優しく揺れる姿が人気です。花は細いリボンのような4枚の花弁があり、春の開花期には枝先に集まるように咲くため株全体が花に覆われ、遠くからでもその美しさが楽しめます。緑の葉に黄色みを帯びた白い花が輝くように映えます。園芸品種には葉に赤みを帯びるものや花色が赤いもの（上写真）もあり周囲の植物との組み合わせも、幅広く楽しめます。","pr":"6月","nt":"","td":"△","so":"砂"},{"n":"トサミズキ","f":"マンサク科","t":"落葉広葉樹","fl":"3～4","h":"3～4","su":"◎～〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"ヒュウガミズキに比べ、花も樹形も大形。横に広がるので、植栽\nスペースが必要。","pr":"花後、紅葉後","nt":"","td":"〇","so":""},{"n":"トチノキ","f":"トチノキ科","t":"","fl":"4～5","h":"15～18","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5月","nt":"","td":"","so":""},{"n":"トベラ","f":"トベラ科","t":"常緑広葉樹","fl":"4～5","h":"2～3","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"カイガラムシ\nアブラムシ","d":"","pr":"秋期～冬期","nt":"","td":"◎","so":""},{"n":"ドラセナ","f":"リュウゼツラン科","t":"","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"","nt":"","td":"","so":""},{"n":"ナギ","f":"マキ科","t":"常緑針葉樹","fl":"","h":"15～18","su":"〇","w":"","c":"△","dw":"〇","al":"","p":"","d":"","pr":"秋期","nt":"","td":"〇","so":""},{"n":"ナツツバキ（シャラノキ）","f":"ツバキ科","t":"","fl":"6～7","h":"12～15","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"7月","nt":"","td":"","so":""},{"n":"ナツハゼ","f":"ツツジ科","t":"落葉広葉樹","fl":"5～6","h":"1～2","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"赤/黄","p":"アブラムシ、ハマキムシ、ハダニ、うどんこ病","d":"花や果実を観賞するだけではなく、果実を生食やジャムなどに加工して楽しむブルーベリーの仲間で、近年人気の高い植物です。日本の平地に自生する植物なので、暑さ寒さに強く、栽培が容易です。紅葉も美しく、姿も野趣に富み、和洋を問わず庭植えすることができます。初夏にハゼノキのように美しい紅葉を見せるためナツハゼと命名されましたが、新芽も赤みを帯びます。葉は両面とも毛に覆われ、ザラザラするのが特徴です。","pr":"12～2月","nt":"","td":"△","so":"砂壌"},{"n":"ナナミノキ","f":"モチノキ科","t":"常緑広葉樹","fl":"6月","h":"5～7","su":"◎～〇","w":"中","c":"〇","dw":"〇","al":"-","p":"カイガラムシ\nハマキムシ","d":"実はモチノキの仲間としては大きい。この実の様子からナナミノキと命名されましたが、語源は「七実の木」、「名の実の木」、「長実の木」と諸説あります。実が目的であれば雌の木を植える。涼しげな葉の様子がモダンなイメージにも合います","pr":"","nt":"","td":"△","so":"湿壌"},{"n":"ナワシログミ","f":"グミ科","t":"常緑広葉樹","fl":"7","h":"2～3","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"7月","nt":"","td":"◎","so":""},{"n":"ナンキンハゼ","f":"トウダイクサ科","t":"落葉広葉樹","fl":"5～6月","h":"5～7","su":"◎～〇","w":"中","c":"◎","dw":"◎","al":"赤/黄","p":"特に見当たらない","d":"秋に赤や黄色の紅葉がとても綺麗な木です。何本も並ぶと見事な景色を作ります。冬の白い実も可愛らしく人気です。四季を感じる木として重宝します。葉の形も丸みがあって愛らしいイメージが強いです。","pr":"3月～4月","nt":"紅葉","td":"〇","so":"全土"},{"n":"ナンテン","f":"メギ科","t":"常緑広葉樹","fl":"6～7月","h":"1～2","su":"◎～△","w":"少","c":"〇","dw":"◎","al":"赤","p":"モザイク\n病葉枯病\nすす病","d":"和名のナンテンは漢名「南天燭」の略とされています。ナンテンは難を転ずることにも通じるため、縁起木、厄よけ、魔よけとして古くから庭に植えられてきました。漢方では、乾燥させた果実を南天実（なんてんじつ）といい、咳止め剤（鎮咳剤）として利用されています。","pr":"","nt":"別品種にシロナンテンがあります。果実は成熟しても赤くならず、やや黄味を帯びた白色の品種です。","td":"△","so":"全土"},{"n":"ナンテン（オタフク）","f":"メギ科","t":"常緑広葉樹","fl":"6月","h":"～0.5","su":"◎","w":"多","c":"△","dw":"△","al":"赤","p":"カイガラムシ\nハマキムシ","d":"ナンテンの矮性種で育て方は同じですが、背丈は低く葉はやや丸みを帯び小さいです。晩秋に紅葉しますが、冬花壇や寄せ植えに利用するようになり一気にポピュラーになりました。庭木としても背丈が低く管理しやすいので利用が増えています。","pr":"2月","nt":"","td":"△","so":"砂壌"},{"n":"ニシキギ","f":"ニシキギ科","t":"落葉広葉樹","fl":"5～7","h":"1～2","su":"◎～〇","w":"少","c":"◎","dw":"◎","al":"赤","p":"・うどんこ病\n・黒星病\n・アブラムシ","d":"ニシキギはその名のごとく「錦」を思わす秋の紅葉の美しさが最大の魅力です。小さな果実は秋の深まりとともに熟して果皮が裂ける蒴果で、晩秋に橙赤色の仮種皮で覆われたタネが垂れ下がる姿もかわいらしいものです。また、緑色の若い枝には浅い土色でコルク質の翼（よく）がある特徴的な枝をもつため、生け花の花材としても好まれます。芽吹きもよく刈り込みにも耐えるので、仕立てものや生け垣としても人気があります。","pr":"冬期（紅葉（10～11月）後）","nt":"","td":"〇","so":"砂壌"},{"n":"ニワウメ","f":"バラ科","t":"落葉広葉樹","fl":"3～4","h":"1～2","su":"〇","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"4月","nt":"","td":"〇","so":""},{"n":"ネコヤナギ","f":"ヤナギ科","t":"","fl":"3～4","h":"4～5","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"4月","nt":"","td":"","so":""},{"n":"ネジキ","f":"ツツジ科","t":"落葉広葉樹","fl":"5～6","h":"4～5","su":"◎～〇","w":"","c":"◎","dw":"△","al":"赤/黄","p":"もち病","d":"名は樹皮がねじれて見えることからついたものです。冬枯れの林でネジキの光沢のある赤い枝と冬芽は可愛く、暖かみを感じさせます。材は緻密だがねじれがあり利用法は限られます。同じツツジ科のアセビ同様に枝葉には有毒成分があり、この成分が解明される以前は家畜が食べて中毒したことも少なくなかったという。","pr":"","nt":"","td":"△","so":"壌"},{"n":"ネズミモチ","f":"モクセイ科","t":"常緑広葉樹","fl":"6月","h":"2～3","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"カイガラムシ\nスス病\n白藻病","d":"ネズミモチの和名は、果実がネズミのふんに似て、葉がモチノキのようであることに由来します。しかし、花は白い煙のようで奇麗ですし、排気ガスにも強いために道路の緑地帯などにも植えられ、比較的生長が遅く樹形を整えやすいため、非常に庭木としては利用価値の高い樹種です。少し名前で損をしているのか、近年使用されることが減ったため、生産量は激減しています。","pr":"6～7月","nt":"","td":"〇","so":"全土"},{"n":"ネムノキ","f":"マメ科","t":"落葉広葉樹","fl":"7","h":"7～10","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"剪定を嫌う。","pr":"3月","nt":"","td":"〇","so":""},{"n":"ノウゼンカズラ","f":"ノウゼンカズラ科","t":"","fl":"7～8","h":"5～7","su":"","w":"","c":"","dw":"","al":"","p":"","d":"古く中国より渡来した植物。茎から付着根を出し、他の樹木や壁\nなどに張り付いて伸びる。","pr":"9月及び冬季","nt":"","td":"","so":""},{"n":"ノムラモミジ","f":"カエデ科","t":"","fl":"","h":"4～5","su":"","w":"","c":"","dw":"","al":"赤","p":"","d":"ノムラという名前は人名ではなく、濃紫＝葉の色からきている。\nまた、かつてこの木は「武蔵野」と呼ばれていた。","pr":"冬期","nt":"","td":"","so":""},{"n":"バイカウツギ","f":"アジサイ科","t":"","fl":"6～7","h":"2～3","su":"","w":"","c":"","dw":"","al":"","p":"","d":"茎が中空のためにウツギの名前がついている。","pr":"","nt":"","td":"","so":""},{"n":"ハイゴケ","f":"苔類","t":"","fl":"","h":"","su":"〇～△","w":"","c":"◎","dw":"◎～〇","al":"","p":"","d":"明るい緑色の三角形の葉が地面に這うように成長します。\n日本ではよく見られるポピュラーな種類です。\n石や木に活着させやすいのでアクアテラリウム*や苔玉等に使用される事も多く重宝されています。","pr":"","nt":"","td":"","so":"砂壌"},{"n":"ハイノキ","f":"ハイノキ科","t":"常緑広葉樹","fl":"４～６","h":"3～4","su":"〇～△","w":"中","c":"△","dw":"△","al":"-","p":"カイガラムシ\nアブラムシ","d":"近畿以西の温暖な地を原産とする常緑樹。涼しげな葉の様子や野趣あふれる樹形が魅力で、近年はシマトネリコと並んで人気の高い木です。成長が緩やかで大きくなりにくいため狭い庭でも管理しやすいのが特徴です。実は黒紫色に熟し、野鳥にとって格好の食糧となります。ハイノキの材から作った灰汁が、染物をする際、染料を繊維に定着させる「媒染剤」に使われたことから名付けられました。材は緻密で将棋の駒や箸、民芸品などを作るのに使われます。","pr":"","nt":"","td":"△","so":"砂壌"},{"n":"ハイビスカス類","f":"アオイ科","t":"","fl":"6～10","h":"2～3","su":"","w":"","c":"","dw":"","al":"","p":"","d":"寿命はほとんど1日限りだが、大輪の品種や涼しい季節は2日\nもつことがある。","pr":"","nt":"","td":"","so":""},{"n":"ハイビャクシン","f":"ヒノキ科","t":"","fl":"4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"カイガラムシ","d":"","pr":"","nt":"","td":"","so":""},{"n":"ハギ","f":"マメ科","t":"","fl":"8～10","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬期","nt":"","td":"","so":""},{"n":"ハクチョウゲ","f":"アカネ科","t":"常緑広葉樹","fl":"5～7","h":"0.5～1.0","su":"◎～〇","w":"","c":"〇","dw":"◎","al":"-","p":"アブラムシ","d":"コンパクトな樹形と、それによく合う小さな花や葉をつけます。刈り込みもきくので様々な使い方ができます。比較的耐陰性があり半日陰でも育ちますが、日当たりが悪いと花つきはよくありません。斑入り種がよく出回っていて、花の咲きにくい半日陰の庭には斑入り種のほうが映えます。漢字では、白丁花と書き、「丁」は花の形のことで簡単にいえば「ラッパ型」を表します。つまり、「白い丁型の花が咲く」ことが命名の由来です。白鳥とは関係がありません。","pr":"8～10月","nt":"","td":"△","so":"全土"},{"n":"ハクチョウソウ","f":"アカバナ科","t":"宿根","fl":"5～11","h":"","su":"◎","w":"","c":"◎","dw":"◎","al":"","p":"アブラムシ　\t赤,ピンク,白,複色","d":"穂状に咲く小花が風に揺れる様子は、白い蝶が群れて飛んでいるようで、やさしい風情が感じられます。性質は強健で耐暑性もあり、初夏から晩秋まで次々と花を咲かせながら株が大きく成長していきます。花壇の背景、コンテナの寄せ植えから、広い場所での景観植物としての利用まで、幅広い用途があります。またフラワーアレンジメントでは空間を埋めるフィラーフラワーとしても使いやすい花です。以前は、草丈1m以上に伸び、白花だけでしたが、近年、濃いピンクの‘シスキューピンク’の育成に始まり、複色、草丈の低いものなど、多くの園芸品種が育成され、利用されるようになりました。","pr":"","nt":"","td":"△","so":"全土"},{"n":"ハクモクレン","f":"モクレン科","t":"落葉広葉樹","fl":"3～4","h":"4～5","su":"◎","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"4月","nt":"","td":"△","so":""},{"n":"ハツユキカズラ","f":"キョウチクトウ科","t":"常緑多年草","fl":"5～6","h":"","su":"〇～△","w":"","c":"〇","dw":"〇","al":"","p":"アブラムシ、カイガラムシ","d":"テイカカズラの園芸品種で、葉は小さく、新葉にピンク色と白の不定形の斑が入る姿が美しい植物です。成長がゆっくりとして、コンパクトにまとまるので扱いやすく、寄せ植えやハンギングバスケット、グラウンドカバーなどに多用されています。枝を長く伸ばして、あんどん仕立てにしたり、フェンスに絡ませることもできます。斑は成長とともに変化し、新芽が出たときは濃いピンク色で、次第に薄くなり、さらに進むと緑色の地に白の斑点となり、やがて緑一色になります。それぞれの生育段階の葉が入り混じるので、成長が活発なときはカラフルです。また、秋から冬に紅葉する姿も美しいです。前年の夏に花芽ができるので、剪定をまめに行っていると、花は咲きません。花後すぐに剪定をすれば小さい白色の花を見ることができます。花は咲き進むとクリーム色に変化します。\n日陰でも育ちますが、あまりに暗いと斑がきれいに出ないので、夏以外は日なたで育てます。","pr":"必要なし","nt":"","td":"△","so":"壌"},{"n":"ハナカイドウ","f":"バラ科","t":"常緑広葉樹","fl":"3～4","h":"4～5","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"5月","nt":"","td":"△","so":""},{"n":"ハナザクロ","f":"ザクロ科","t":"","fl":"6～8","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"2～3月","nt":"","td":"","so":""},{"n":"ハナズオウ","f":"キク科","t":"落葉広葉樹","fl":"4～5","h":"3～4","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"5月","nt":"","td":"〇","so":""},{"n":"ハナノキ","f":"ムクロジ科","t":"落葉広葉樹","fl":"4","h":"15～18","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"冬期","nt":"","td":"〇","so":""},{"n":"ハナミズキ","f":"ミズキ科","t":"常緑広葉樹","fl":"4～5","h":"7～10","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"","pr":"11～3月","nt":"紅葉","td":"◎","so":""},{"n":"ハナモモ","f":"バラ科","t":"","fl":"3～4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"花後","nt":"","td":"","so":""},{"n":"ハマヒサカキ","f":"モッコク科","t":"常緑広葉樹","fl":"10～12月","h":"1～2","su":"◎～〇","w":"少","c":"◎","dw":"◎","al":"","p":"カイガラムシ\nスス病\nホタルガ","d":"","pr":"年中","nt":"","td":"◎","so":"全土"},{"n":"バラ類","f":"バラ科","t":"","fl":"5～12","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"1～2月、9月","nt":"","td":"","so":""},{"n":"ハンカチノキ","f":"ミズキ科","t":"","fl":"5～6","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月","nt":"","td":"","so":""},{"n":"ヒイラギ","f":"モクセイ科","t":"常緑針葉樹","fl":"10～12","h":"7～10","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"初冬に芳香のある白色の花が見られる。花の少ない時期の貴重な樹木。縁起木としても使われる。","pr":"7月","nt":"","td":"〇","so":""},{"n":"ヒイラギナンテン","f":"メギ科","t":"常緑広葉樹","fl":"3～4","h":"1～2","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"葉がヒイラギに、果実がナンテンに似ることから名がついた。","pr":"いつでも可","nt":"","td":"〇","so":""},{"n":"ヒイラギモクセイ","f":"モクセイ科","t":"常緑広葉樹","fl":"11～12月","h":"5～7","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"葉は先が尖った長楕円形で、棘状の鋭い鋸歯があり、対生する。\n10月頃、葉腋に白い花を束生させ、わずかに芳香のある花を咲か\nせる。日本にある株のほとんどが雄株なので、結実はしない。","pr":"秋期","nt":"","td":"〇","so":""},{"n":"ヒサカキ","f":"ツバキ科","t":"常緑広葉樹","fl":"2～4","h":"7～10","su":"◎～△","w":"","c":"〇","dw":"〇","al":"","p":"","d":"年間を通じて艶サカキ同様に縁起の良い木とされ、神棚へ供える\n玉串に使われる。サカキよりも耐寒性がある。","pr":"4～7月","nt":"","td":"〇","so":""},{"n":"ヒペリカム","f":"オトギリソウ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"11～2月","nt":"","td":"","so":""},{"n":"ヒマラヤスギ","f":"マツ科","t":"常緑針葉樹","fl":"10～11","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6～7月","nt":"","td":"","so":""},{"n":"ヒマラヤヤマボウシ","f":"ミズキ科","t":"常緑広葉樹","fl":"5～7","h":"7～10","su":"◎","w":"中","c":"〇","dw":"△","al":"","p":"テッポウムシ\nイラガ\nミノムシ\nカイガラムシ\nうどんこ病","d":"通常ヤマボウシは落葉樹ですが、この品種は外来種で常緑です。見た目は通常のヤマボウシとそっくりですが、冬期に葉が残ります。花は小さめで少し黄色がかっています。冬期に北西の風が直接当たるところでは葉や枝先が傷むことがあります。","pr":"","nt":"実は食べられる","td":"△","so":"砂質壌土"},{"n":"ヒメクチナシ（コクチナシ）","f":"アカネ科","t":"常緑広葉樹","fl":"6～7","h":"～0.5","su":"〇～△","w":"","c":"〇","dw":"△","al":"","p":"褐色円星病\nさび病\nすす病\nオオスカシバ\nカイガラムシ\nアブラムシ\nロウムシ\nオンシツコナジラミ","d":"クチナシの近縁種で、全体的に小さくしたような木です。梅雨どきに純白の花を咲かせて強い香りを漂わせます。秋には橙赤色の果実をつけます。地表を這うように枝が横に広がります。グランドカバーとして使われることが多いです。","pr":"7～8月","nt":"","td":"△","so":"埴壌"},{"n":"ヒメシャガ","f":"アヤメ科","t":"宿根","fl":"5～6月","h":"","su":"〇～△","w":"","c":"◎","dw":"〇～△","al":"","p":"ハダニ","d":"山地の森林にある岩場や急斜面に見られます。草丈は低く、葉が薄くて光沢はなく、冬には地上部が枯れる点でシャガとは簡単に区別できます。短く横に這う根茎があり、多数のひげ根が生えています。初夏に葉の間から斜めに花茎を伸ばし、先端近くに数輪の花を咲かせます。","pr":"","nt":"","td":"△","so":""},{"n":"ヒメシャラ","f":"ツバキ科","t":"落葉広葉樹","fl":"5～6","h":"12～15","su":"◎","w":"","c":"〇","dw":"〇","al":"赤","p":"チャドクガ","d":"樹皮や初夏に咲く控えめな花の雰囲気が好まれ、古くから庭木として寺院や茶庭に使われる。新緑や紅葉も美しく、全般に明るい雰\n気を持つことからシンボルツリーとして一般家庭の玄関付近に植栽される例も多い。","pr":"6月","nt":"","td":"△","so":""},{"n":"ヒメリンゴ","f":"バラ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"12～翌3月","nt":"","td":"","so":""},{"n":"ヒュウガミズキ","f":"マンサク科","t":"落葉広葉樹","fl":"3～4","h":"1～2","su":"◎","w":"","c":"〇","dw":"〇","al":"赤/黄","p":"うどんこ病","d":"近畿地方(石川県から兵庫県)の日本海側の限られた地域の岩場に自生しています。花は、葉が出るよりも早く3月下旬に2～3個の丸みのある黄白色の小花が花序になって、数多く下垂します。枝は細くたくさん分岐し、半球状の整った樹形になります。刈り込んで樹形を整えることが簡単にできるので、樹形づくりを楽しむことができます。","pr":"5月","nt":"","td":"〇","so":"埴壌"},{"n":"ビョウヤナギ","f":"オトギリソウ科","t":"","fl":"6～7","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"7月","nt":"","td":"","so":""},{"n":"ピラカンサ類","f":"バラ科","t":"常緑広葉樹","fl":"5～6","h":"1～2","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"4～8月","nt":"","td":"〇","so":""},{"n":"ヒラドツツジ","f":"ツツジ科","t":"常緑広葉樹","fl":"4～5","h":"0.5～1.0","su":"◎～〇","w":"少","c":"〇","dw":"〇","al":"-","p":"褐斑病、花腐菌核病、もち病、\n・ツツジグンバイムシ、ハダニ","d":"長崎県平戸市に植えられていたケラマツツジ、日本産のモチツツジ、キシツツジなどとの間で自然交雑が生じ、その変異品種から選抜されたのがヒラドツツジとされています。約300種が命名されています。","pr":"5月","nt":"","td":"〇","so":"全土"},{"n":"ビワ","f":"バラ科","t":"","fl":"11～2","h":"7～10","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"7月","nt":"","td":"","so":""},{"n":"フィリフェラオーレア","f":"ヒノキ科","t":"常緑針葉樹","fl":"","h":"2～3","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"","p":"ミノガ","d":"黄色の葉色がきれいです。冬の葉色はあまり変わりません。柔らかくて触れても痛くありません。刈り込まれて、グランドカバーや境裁で用いられることが多いですが、自然樹形は広円錐形になります。各地の植物園などで大きな樹木になった姿を見ることができますが、庭木としては低木としての利用がほとんどです。","pr":"","nt":"","td":"〇","so":"砂壌"},{"n":"フウチソウ","f":"イネ科","t":"宿根","fl":"8～9","h":"","su":"〇","w":"","c":"◎","dw":"◎～〇","al":"","p":"","d":"本州の太平洋側の地域の特産種です。多数の茎が株立ちになって垂れ下がり、数枚の長さ15cm前後の細長い葉をつけます。この葉はつけ根でねじ曲がっていて、表が裏に、裏が表になっているので「裏葉草」という名になっています。8月から9月に茎の先端に細かな穂をつけますが、地味な色合いです。冬は全体に黄色く黄葉したあと、地上部は茶色く枯れて冬越しします。","pr":"","nt":"","td":"△","so":"全土"},{"n":"フェイジョア","f":"フトモモ科","t":"常緑広葉樹","fl":"5～6月","h":"1～2","su":"◎～〇","w":"","c":"〇","dw":"〇","al":"","p":"アブラムシ\nハダニ\nハマキムシ\nうどんこ病","d":"花から果実まで楽しめる丈夫な常緑低木。花弁は内側が赤褐色、外側が白色で分厚く、糖分を含んで甘みがあります。日本では1980年代にキウィフルーツに続く新果樹として注目されたこともありました。近年では家庭果樹として見直され、ポポーに並びブームになっています。葉の裏が白く目立つため、デザイン的にも面白みがあります。","pr":"","nt":"","td":"△","so":"全土"},{"n":"フサアカシア（ミモザ）","f":"マメ科","t":"常緑広葉樹","fl":"3～4","h":"12～15","su":"◎～〇","w":"","c":"△","dw":"◎","al":"黄","p":"カイガラムシ","d":"葉の表、裏共に青緑白色で無毛","pr":"冬期","nt":"","td":"〇","so":"砂壌"},{"n":"フジバカマ","f":"キク科","t":"宿根","fl":"8～9","h":"","su":"◎～〇","w":"","c":"◎","dw":"△","al":"","p":"コナジラミ、アブラムシ、ハダニ、コナガ","d":"「秋の七草」の一つで、万葉の時代から人々に親しまれてきた植物です。夏の終わりから秋の初め、茎の先端に直径5mmほどの小さな花を、長さ10cm前後の房状に多数咲かせます。川沿いの湿った草原やまばらな林に見られ、まっすぐに伸びる茎に、3裂する葉が対になってつきます。地下茎が大量に伸びて猛烈な勢いで広がるため、自生地では密生した群落になるのが普通ですが、現在の日本には自生に適した環境が少なくなったため激減し、絶滅危惧種となっています。フジバカマの名で市販されているものの多くは、サワフジバカマ（フジバカマとサワヒヨドリの雑種）です。","pr":"","nt":"","td":"△","so":"壌"},{"n":"フジ類","f":"マメ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"12～2月","nt":"","td":"","so":""},{"n":"フッキソウ","f":"ツゲ科","t":"常緑多年草","fl":"4～5月","h":"","su":"〇～△","w":"中","c":"◎","dw":"〇","al":"","p":"ほとんどない","d":"","pr":"","nt":"","td":"△","so":"全土"},{"n":"ブッドレア類","f":"フジウッギ科","t":"","fl":"7～10","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"11～3月","nt":"","td":"","so":""},{"n":"フデゴケ","f":"苔類","t":"","fl":"","h":"","su":"〇～△","w":"","c":"◎","dw":"◎","al":"","p":"","d":"葉が筆のようにきめ細やかで美しいのが特徴です。\nホソバオキナゴケやアラハシラガゴケと同様にコケリウム内の芝生を作るのに向いています。深い緑色をしているのでレイアウトは落ち着いた雰囲気になります。\n光はスナゴケやスギゴケと同様にしっかり当ててやると綺麗に育ちます。","pr":"","nt":"","td":"","so":"砂壌"},{"n":"フヨウ","f":"アオイ科","t":"","fl":"7～10","h":"3～4","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"落葉期","nt":"","td":"","so":""},{"n":"ブラシノキ","f":"フトモモ科","t":"常緑広葉樹","fl":"5～6","h":"2～3","su":"◎～〇","w":"","c":"△","dw":"◎","al":"","p":"","d":"別名、カリステモン、キンポウジュ、ボトルブラッシュ、ボトルブラシ。カリステモン属は、オーストラリア全域からニューカレドニアに30種が分布する低木から高木の常緑性花木。花の形が瓶を洗うブラシに似ているとしてブラシノキと名付けられる。生長すると上部が重くなって倒れやすい木であるため、支柱を必要とする。","pr":"","nt":"","td":"△","so":"砂壌"},{"n":"ブルーパシフィック","f":"ヒノキ科","t":"常緑針葉樹","fl":"","h":"","su":"◎～〇","w":"少","c":"◎","dw":"〇","al":"","p":"ほとんどない","d":"地を這うように伸びていく針葉樹の低木です。高さが高くなりにくいので、刈込などのメンテナンスが少なくて済みます。非常に丈夫で場所を選ばず生長できる性質です。生長して密度が高まり地面を覆えば雑草抑制の効果も期待できます。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"ヘデラ・カナリエンシス","f":"ウコギ科","t":"常緑ツル性","fl":"","h":"～0.1","su":"◎～△","w":"","c":"◎","dw":"◎","al":"","p":"・立枯病\n・炭疽病\nハダニ\nカイガラムシ","d":"環境適応力が広く、他の地被植物に比べ手間がかからないため、大面積利用の地被として最も利用されています。ヘデラヘリックスに比べ、葉は大型で光沢があります。常緑ですが、冬期はやや赤味を帯びた緑になります。","pr":"","nt":"","td":"◎","so":"全土"},{"n":"ボケ","f":"バラ科","t":"落葉広葉樹","fl":"3～4","h":"1～2","su":"◎","w":"","c":"◎","dw":"〇","al":"","p":"","d":"花色が豊富で、真冬に咲く品種や開花時期が長い品種がある。","pr":"11月以降","nt":"","td":"〇","so":""},{"n":"ホソバヒイラギナンテン","f":"メギ科","t":"常緑広葉樹","fl":"9～11","h":"～0.5","su":"〇～△","w":"","c":"△","dw":"〇～△","al":"","p":"うどんこ病","d":"別名：ヤナギバヒイラギナンテン、マホニア・コンフーサ\n日陰に強く、他の花が少ない時季に開花すること、病害虫の被害が少ないこと、日本の木にはないエスニックな雰囲気を持つことなどから、近年では和洋問わず多くの庭園や公園、街路、ショッピングモールなどに使われる。ヤシやソテツなどと共に植栽し、アジアンリゾートを演出するような使い方も多いです。ヒイラギナンテンに比べると葉の幅は広いが、縁のギザギザが浅く、質感も柔らかであり、手で触れてもチクチクしません。場所によっては花にスズメバチが来ることがあり注意が必要です。","pr":"","nt":"","td":"△","so":"壌"},{"n":"ボタン","f":"ボタン科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月、落葉期","nt":"","td":"","so":""},{"n":"ボックスウッド（セイヨウツゲ）","f":"ツゲ科","t":"常緑広葉樹","fl":"3～4月","h":"0.5～1.0","su":"◎～〇","w":"","c":"〇","dw":"〇","al":"","p":"ハマキムシ\nツゲノメイガ","d":"名前の由来は刈り込みの形ではなく、材が緻密で、箱を作るのに適していることからきています。比較的手入れがしやすい植物です。ツゲの仲間で生垣などに良く使われます。生垣というと和風のイメージですが、ボックスウッドは葉の色が明るいことから洋風住宅にも良く合うといえるでしょう。開花時期には、白い花と素敵な香りを楽しむことができます。","pr":"3、7、10月","nt":"","td":"△","so":"全土"},{"n":"ホトトギス","f":"ユリ科","t":"宿根","fl":"8～9","h":"","su":"〇～△","w":"","c":"〇","dw":"◎～〇","al":"","p":"白、ピンク、紫、黄\n白絹病","d":"日本の特産種で主に太平洋側に自生する多年草です。日陰のやや湿った斜面や崖、岩場に見られ、葉のわきに、直径2～3cmで紫色の斑点のある花を1～3輪上向きに咲かせます。茎はふつう枝分かれせず、まっすぐか斜めに伸び、場所や地域によっては弓なりに垂れることもあります。斑入りの園芸品種も流通しています。","pr":"","nt":"","td":"△","so":"壌"},{"n":"マサキ","f":"ニシキギ科","t":"常緑広葉樹","fl":"6～7","h":"1～2","su":"◎～△","w":"中","c":"◎","dw":"◎～〇","al":"-","p":"うどんこ病\nカイガラムシ\nシャクトリムシ\nミノウスバ","d":"マサキは土地を選ばず耐陰性も強い為に、環境が悪くても生育できます。緑色のつやがある少し大きめの枝に楕円形の光沢がある革質の葉をつけます。若い葉は黄色になり成熟するにしたがって緑色になります。葉が観賞価値が高く庭木に利用されます。生垣にも使用でき刈り込むと枝葉が密になります。生け花材としても利用されます。葉に斑の入る種類もあります。","pr":"秋期（いつでも可）","nt":"","td":"◎","so":"全土"},{"n":"マツ","f":"マツ科","t":"","fl":"4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"10～3月（揉み上げ）、5月（みどり摘み）","nt":"","td":"","so":""},{"n":"マテバシイ","f":"ブナ科","t":"常緑広葉樹","fl":"6","h":"10～12","su":"◎～〇","w":"少","c":"〇","dw":"〇～△","al":"-","p":"カイバラムシ\nアブラムシ","d":"防風、防火など実用的な理由から工場や寺社、学校などに植栽されていましたが、虫がほとんどつかない点を見込まれ、次第に公園や庭園などでも用いられるようになりました。防音効果も期待できます。１本の幹が直立するのが基本ですが、根元から複数が生じる株立ち樹形もあります。","pr":"秋期","nt":"","td":"◎","so":"全土"},{"n":"マユミ（ヤマニシキギ）","f":"ニシキギ科","t":"落葉広葉樹","fl":"5～6","h":"3～4","su":"◎～〇","w":"中","c":"◎","dw":"◎","al":"赤/黄","p":"アブラムシ\nアザミウマ\nカイガラムシ\nうどんこ病","d":"マユミは日本に自生する植物なので、栽培は容易で、病害虫もほとんどなく、日なたに植えれば、毎年美しい紅葉と果実を楽しむことができます。木の質は緻密で、粘りがあり、古くはマユミの木で弓をつくったことから「真弓」と呼ばれるようになったといわれます。現在でも将棋の駒などの材料として利用されます。マユミの小さい版という意味で「コマユミ」という種類もも別にあります。","pr":"11～3月","nt":"","td":"△","so":"全土"},{"n":"マンサク","f":"マンサク科","t":"落葉広葉樹","fl":"2～3","h":"2～3","su":"◎～〇","w":"中","c":"◎","dw":"△","al":"黄","p":"うどんこ病\nカイガラムシ","d":"マンサクは冬の名残のある野山などで、木々の芽吹きも始まらない季節に、黄色の花を咲かせ、いち早く春の訪れを告げる花木です。花がよく咲けば豊作、花が少なければ不作など、稲の作柄を占う植物として古くから人との深いつながりをもっていました。そこから満作の名がついたとも、開花期が早いことから「まず咲く」や「真っ先」が変化したともいわれています。\n落葉期に咲くため、小さいながらも花がよく目立ちます。美しい紅葉も楽しめ（10月中旬から11月）、水平に伸びる枝には整然とした美しさがあります。成長が遅いので、狭い場所にも植えることができます。","pr":"花後","nt":"","td":"△","so":"壌"},{"n":"マンリョウ","f":"サクラソウ科","t":"常緑広葉樹","fl":"7月","h":"～0.5","su":"〇～△","w":"","c":"△","dw":"〇","al":"","p":"ごくまれにカイガラムシがつくことがあります。春、幼虫の発生期に薬剤を散布して、防除します。","d":"大きな赤い果実をつけるマンリョウは、果実と常緑の濃緑色の葉を観賞する縁起植物として親しまれています。江戸時代から実色が違ったり、葉に斑が入ったり縮れたりするものなど園芸化が進んだ古典園芸植物です。その後、明治に多くの品種が作出され、また昭和初期にも流行しました。","pr":"秋期","nt":"","td":"△","so":"砂壌"},{"n":"ミカン","f":"ミカン科","t":"","fl":"5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"2～3月","nt":"","td":"","so":""},{"n":"ミズキ","f":"ミズキ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5月","nt":"","td":"","so":""},{"n":"ミツマタ","f":"シキミ科","t":"落葉広葉樹","fl":"3～4","h":"1～2","su":"〇","w":"","c":"〇","dw":"〇～△","al":"","p":"","d":"","pr":"5月","nt":"","td":"〇","so":""},{"n":"ムクゲ","f":"アオイ科","t":"落葉広葉樹","fl":"7～9","h":"2～3","su":"◎～〇","w":"中","c":"◎","dw":"◎～〇","al":"-","p":"アブラムシ\nカミキリムシ\nハマキムシ","d":"","pr":"10月","nt":"","td":"〇","so":"全土"},{"n":"ムサシノケヤキ","f":"ニレ科","t":"落葉広葉樹","fl":"4","h":"15～18","su":"◎","w":"多","c":"◎","dw":"△","al":"赤/黄","p":"アブラムシ\n褐斑病","d":"樹形の美しいケヤキの非常に幅の細い木が埼玉県で発見されました。その後増やしてムサシノと名づけられました。美しいケヤキですが、非常に大きくなるため街路樹や建物周りに植えるときには場所を取ります。そこで、幅が1/3程度のこのケヤキを植えるようにと全国へ広がっていきました。","pr":"2～3月","nt":"黄紅葉","td":"〇","so":"湿壌"},{"n":"ムラサキシキブ","f":"シソ科","t":"","fl":"6～7","h":"2～3","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"11～2月","nt":"","td":"","so":""},{"n":"モクセイ","f":"モクセイ科","t":"","fl":"9～10","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"花後","nt":"","td":"","so":""},{"n":"モチノキ","f":"モチノキ科","t":"常緑広葉樹","fl":"4～5月","h":"5～7","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"","p":"カイガラムシ\nスス病","d":"樹皮から鳥黐（トリモチ）を作ることができ、これが名前の由来ともなりました。古くから庭木の三大名木となされて人気があります。高木の中では比較的成長が遅いので管理がしやすい木です。「持ち」の木とし、財産や子孫など必要なものを持つことができるとして縁起木とされます。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"モッコク","f":"ツバキ科","t":"","fl":"7～8","h":"12～15","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"秋期","nt":"","td":"","so":""},{"n":"モミジバフウ","f":"マンサク科","t":"","fl":"4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"","nt":"紅葉・実","td":"","so":""},{"n":"モモ（ハナモモ）類","f":"バラ科","t":"","fl":"3～4","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"5～6月","nt":"","td":"","so":""},{"n":"ヤツデ","f":"ウコギ科","t":"常緑広葉樹","fl":"10～12","h":"2～3","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"4～6月","nt":"","td":"◎","so":""},{"n":"ヤナギ","f":"ヤナギ科","t":"","fl":"3～6","h":"1～2","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"2月","nt":"","td":"","so":""},{"n":"ヤブツバキ","f":"ツバキ科","t":"常緑広葉樹","fl":"2～4","h":"3～4","su":"◎～△","w":"中","c":"◎","dw":"〇","al":"","p":"チャドクガ","d":"古くから日本人に親しまれた庭木です。艶のある葉が特徴的です。冬期の花の少ない時期に見事に咲く花として重宝されてきました。一般的にツバキと呼ばれるのはこの品種をいいます。ツバキは他にもたくさんの品種があり、改良されています。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"ヤブニッケイ","f":"クスノキ科","t":"常緑広葉樹","fl":"6","h":"15～18","su":"◎","w":"","c":"△","dw":"〇","al":"","p":"","d":"","pr":"2～3月、6～10月","nt":"","td":"〇","so":""},{"n":"ヤブラン","f":"キジカクシ科","t":"常緑多年草","fl":"8～10","h":"","su":"◎～△","w":"","c":"◎","dw":"◎～〇","al":"","p":"・ナメクジ\n・霜にあたると葉が萎れます。\n・斑入りの品種もあります。","d":"日本各地の林床などで普通に見られる常緑性の多年草です。ほぼ一年中同じ草姿を保ち、性質が強く、丈夫で手のかからない植物なので、古くから緑化や造園の植栽材料として広く利用されています。耐寒性と耐暑性が強く、日なたから日陰まで幅広い環境に適応し、病害虫の被害もほとんど見られず、土質もあまり選びません。","pr":"","nt":"","td":"〇","so":"全土"},{"n":"ヤマブキ","f":"バラ科","t":"落葉広葉樹","fl":"3～6","h":"0.5～1.0","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"黄","p":"ハダニ","d":"美しい山吹色の花が咲くので『万葉集』にも詠まれるなど、古くから観賞されてきました。山吹色はまさにこの花の色をいいます。また、シロヤマブキと混同されることがありますが、ヤマブキとシロヤマブキは別属の植物で、ヤマブキは花が5弁（シロヤマブキは4弁）、葉が互生（シロヤマブキは対生）であることで、容易に区別できます。","pr":"11～2月（冬期）","nt":"","td":"△","so":"全土"},{"n":"ヤマボウシ","f":"ミズキ科","t":"落葉広葉樹","fl":"5～7","h":"5～7","su":"◎～〇","w":"中","c":"◎","dw":"△","al":"紅","p":"テッポウムシ\nイラガ\nミノムシ\nカイガラムシ\nうどんこ病","d":"自然でやわらかい樹形と細い風に揺られる枝で非常に人気。樹形は横に広がりながら全体に丸い形に大きくなります。花は葉の上に咲くことから、上から見られる場所が見やすくなります。","pr":"","nt":"実は食べられる","td":"〇","so":"砂壌"},{"n":"ヤマボウシ・月光","f":"ミズキ科","t":"常緑広葉樹","fl":"5～7","h":"5～7","su":"◎","w":"中","c":"〇","dw":"△","al":"","p":"テッポウムシ\nイラガ\nミノムシ\nカイガラムシ\nうどんこ病","d":"通常ヤマボウシは落葉樹ですが、この品種は外来種で常緑です。見た目は通常のヤマボウシとそっくりですが、冬期に葉が残ります。花が大きめで満開時は見事です。月光は特に花付きが良いとされますが、日照量が少ないと花付も落ちます。冬期に北西の風が直接当たるところでは葉や枝先が傷むことがあります。","pr":"","nt":"実は食べられる","td":"△","so":"砂質壌土"},{"n":"ヤマモモ","f":"ヤマモモ科","t":"常緑広葉樹","fl":"3～4","h":"10～12","su":"〇","w":"","c":"〇","dw":"〇","al":"","p":"","d":"","pr":"4月","nt":"","td":"〇","so":"全土"},{"n":"ユキヤナギ","f":"バラ科","t":"落葉広葉樹","fl":"3～4","h":"1～2","su":"◎～〇","w":"","c":"◎","dw":"〇","al":"赤/黄","p":"うどんこ病\nカイガラムシ\nアブラムシ","d":"ユキヤナギは春、枝垂れた枝先の長い穂に、たくさんの花を咲かせてひときわ目を引き、花壇や公園によく植えられている植物です。ユキヤナギの和名は、葉がヤナギに似て、白い多数の花が、雪をかぶったように見えることからつけられました。庭木としてだけではなく、切り花としてもよく利用されます。強健で、生育も非常に旺盛なので、花後に地際から刈り込んでも、秋までに新梢が1m以上伸び、翌年もよく開花します。","pr":"4月","nt":"","td":"△","so":"全土"},{"n":"ユズ","f":"ミカン科","t":"","fl":"5～6","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬期","nt":"","td":"","so":""},{"n":"ユスラウメ","f":"バラ科","t":"","fl":"4～5","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"11～翌3月","nt":"","td":"","so":""},{"n":"ヒメユズリハ","f":"ユズリハ科","t":"常緑広葉樹","fl":"5～6","h":"5～7","su":"◎～〇","w":"","c":"◎","dw":"◎～〇","al":"","p":"カイバラムシ、アブラムシ、さび病","d":"「譲り葉」の由来: 春に新しい若葉が一斉に芽吹いて成長してから、古い葉が落ちるという世代交代のような特徴的な生育サイクルを持ちます。この様子が「親が子に代を譲る」ことに例えられ、子孫繁栄や家系の繁栄を願う縁起の良い木として、正月飾りなどに用いられます。","pr":"6～7月、11～12月","nt":"","td":"◎","so":"全土"},{"n":"ユリノキ","f":"モクレン科","t":"","fl":"6～7","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6～7月、11～12月","nt":"","td":"","so":""},{"n":"ライラック","f":"モクセイ科","t":"落葉広葉樹","fl":"4～5","h":"2～3","su":"〇","w":"","c":"◎","dw":"〇","al":"赤/黄","p":"アブラムシ、カイガラムシ、うどんこ病","d":"ライラックの主な特徴は、甘い香りの花、ハート形の葉、房状に咲く花姿です。花色は豊富で、紫、白、ピンクなどがあり、香水やアロマオイルの原料としても利用されます。また、香りが良いため「思い出」や「友情」といった花言葉を持ち、冷涼な気候を好みます。","pr":"花後","nt":"","td":"△","so":"壌"},{"n":"ラカンマキ","f":"マキ科","t":"常緑針葉樹","fl":"5～6","h":"3～4","su":"◎～〇","w":"","c":"〇","dw":"◎～〇","al":"-","p":"ハマキムシ、カイガラムシ、アブラムシ","d":"イヌマキの変種でイヌマキ同様に、庭木として広く使われます。イヌマキよりも葉は短くて白味を帯び、個体によっては葉先が黄色っぽくなります。ラカンマキはイヌマキよりも成長が緩やかであり、その分樹形が引き締まって乱れにくいため、価値が高いとされます。樹高もイヌマキより低く、５ｍ以下のものが多いです。果実はイヌマキと同じですが、実がなるのは稀とされます。実の形が、袈裟をまとった僧侶（羅漢）に見えるとして、ラカンマキと名付けられました。イヌマキ同様、赤い部分（花托）はおいしいが、黒い部分（実托）は毒性があって食べられません。幹は灰白色で成長に伴って縦に薄く剥がれ落ちる。材は良質で、建材や器具類に使われます。","pr":"秋期","nt":"","td":"〇","so":"全土"},{"n":"ラベンダー","f":"シソ科","t":"落葉広葉樹","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"","nt":"","td":"","so":""},{"n":"リキュウバイ","f":"バラ科","t":"落葉広葉樹","fl":"5～6","h":"3～4","su":"◎","w":"中","c":"◎","dw":"〇","al":"","p":"","d":"春に白い花沢山咲かせます、派手すぎない花と趣のある枝ぶりが茶人に好まれ、茶花としてよく利用されています。リキュウバイ(利休梅)の名は、茶花として広く利用されていたことや千利休命日の頃に咲くなどに由来しているといわれます。樹形は素直にまっすくというよりは自由奔放に伸びていきます。","pr":"1～2月","nt":"","td":"〇","so":"壌土"},{"n":"リュウノヒゲ","f":"キジカクシ科","t":"常緑多年草","fl":"7～8月","h":"","su":"◎～△","w":"中","c":"◎","dw":"〇","al":"","p":"ほとんどない","d":"","pr":"","nt":"","td":"△","so":"全土"},{"n":"リョウブ","f":"リョウブ科","t":"","fl":"7～9","h":"7～10","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"1～2月","nt":"","td":"","so":""},{"n":"リンゴ","f":"バラ科","t":"","fl":"","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"冬期","nt":"","td":"","so":""},{"n":"レモン","f":"ミカン科","t":"","fl":"5～6","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"2～3月","nt":"","td":"","so":""},{"n":"レンギョウ","f":"モクレン科","t":"落葉広葉樹","fl":"3～4","h":"0.5～1.0","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"赤/黄","p":"うどんこ病\nカイガラムシ\n紋羽病\nアオバハゴロモ","d":"英語ではゴールデンベルと呼ばれ、その名のとおり３～４月になると枝一面に鈴のような黄色い花を鮮やかに咲かせます。日本には300年ほど前に薬用として渡来しましたが、現在では花の観賞用が中心となっています。 もちろん、漢方薬としても使われていて、解毒、排膿、消炎、利尿に薬効があります。","pr":"花後、6月","nt":"","td":"〇","so":"全土"},{"n":"ロウバイ","f":"ロウバイ科","t":"落葉広葉樹","fl":"12～2","h":"2～3","su":"◎～〇","w":"","c":"◎","dw":"◎","al":"黄","p":"・うどんこ病\n・黒星病\n・アブラムシ","d":"ロウバイはまるでロウ細工のような黄色い花を咲かせる、中国原産の落葉低木です。開花期以外はあまり目立ちませんが、新春に香り高い花を咲かせる貴重な存在です。中国では、ウメ、スイセン、ツバキとともに、「雪中の四花」として尊ばれています。江戸時代初期に日本へ渡来し、ほかの花木に先駆けて咲く香りのよい花が愛され、生け花や茶花、庭木として利用されてきました。","pr":"花後、5月","nt":"","td":"△","so":"砂壌"},{"n":"ローズマリー","f":"シソ科","t":"","fl":"不定期(3～4月が多い)","h":"","su":"","w":"","c":"","dw":"","al":"","p":"","d":"","pr":"6月","nt":"","td":"","so":""}];